export const runtime = "nodejs";

import { NextRequest, NextResponse } from "next/server";
import path from "path";
import fs from "fs/promises";
import { createReadStream } from "fs";
import { randomUUID } from "crypto";
import { z } from "zod";
import OpenAI, { toFile } from "openai";
import sharp from "sharp";

import { apiHandler } from "@/shared/lib/api/api-handler";
import type { ApiHandlerContext } from "@/shared/types/api";
import { createErrorResponse } from "@/shared/lib/api/handle-api-error";
import { badRequestError, configurationError, operationFailedError } from "@/shared/errors/app-error";

import { getImageFileRepository } from "@/features/files/server";
import type { ImageFileRecord } from "@/shared/types/files";
import { parseImageStudioSettings } from "@/features/ai/image-studio/utils/studio-settings";
import { getSettingValue } from "@/features/products/services/aiDescriptionService";

const projectsRoot = path.join(process.cwd(), "public", "uploads", "studio");
const publicRoot = path.join(process.cwd(), "public");

const pointSchema = z.object({
  x: z.number().min(0).max(1),
  y: z.number().min(0).max(1),
});

const polygonSchema = z.array(pointSchema).min(3);

const maskSchema = z.union([
  z.object({
    type: z.literal("polygon"),
    points: polygonSchema,
    closed: z.boolean(),
  }),
  z.object({
    type: z.literal("polygons"),
    polygons: z.array(polygonSchema).min(1),
    invert: z.boolean().optional(),
    feather: z.number().min(0).max(50).optional(),
  }),
]);

const runSchema = z.object({
  projectId: z.string().min(1).max(120),
  asset: z.object({
    filepath: z.string().min(1),
    id: z.string().optional(),
  }),
  prompt: z.string().min(1),
  mask: maskSchema.nullable().optional(),
  studioSettings: z.unknown().optional(),
});

const sanitizeProjectId = (value: string): string =>
  value.trim().replace(/[^a-zA-Z0-9-_]/g, "_");

const resolveAssetPath = (filepath: string): string => {
  const normalized = filepath.replace(/^\/+/, "");
  return path.resolve(publicRoot, normalized);
};

const ensureWithinProject = (diskPath: string, projectId: string): void => {
  const projectRoot = path.resolve(projectsRoot, projectId);
  if (!diskPath.startsWith(`${projectRoot}${path.sep}`)) {
    throw badRequestError("Asset path is outside the project.");
  }
};

const toOutputFolder = (projectId: string): string =>
  path.join(projectsRoot, projectId, "outputs");

const mapBackground = (value: string | null | undefined): "transparent" | "opaque" | "auto" | null => {
  if (!value) return null;
  if (value === "transparent") return "transparent";
  if (value === "white") return "opaque";
  return "auto";
};

const coerceImageSize = (value: string | null | undefined): OpenAI.Images.ImageEditParams["size"] => {
  if (!value) return undefined;
  const allowed = new Set([
    "auto",
    "256x256",
    "512x512",
    "1024x1024",
    "1536x1024",
    "1024x1536",
  ]);
  return allowed.has(value) ? (value as OpenAI.Images.ImageEditParams["size"]) : undefined;
};

async function buildMaskBuffer(params: {
  imagePath: string;
  polygons: Array<Array<{ x: number; y: number }>>;
  invert?: boolean;
  feather?: number;
}): Promise<Buffer | null> {
  const metadata = await sharp(params.imagePath).metadata();
  const width = metadata.width ?? null;
  const height = metadata.height ?? null;
  if (!width || !height) return null;

  const polygons = params.polygons
    .map((poly) => poly.map((p) => `${Math.round(p.x * width)},${Math.round(p.y * height)}`).join(" "))
    .map((points) => `<polygon points="${points}" fill="${params.invert ? "white" : "black"}" fill-opacity="${params.invert ? 1 : 0}" />`)
    .join("\n");

  const svg = `<svg width="${width}" height="${height}" viewBox="0 0 ${width} ${height}" xmlns="http://www.w3.org/2000/svg">
  <rect width="100%" height="100%" fill="${params.invert ? "black" : "white"}" fill-opacity="${params.invert ? 0 : 1}" />
  ${polygons}
</svg>`;

  let output = sharp(Buffer.from(svg));
  if (params.feather && params.feather > 0) {
    output = output.blur(Math.min(10, params.feather / 10));
  }
  return output.png().toBuffer();
}

async function createImageRecord(params: {
  projectId: string;
  buffer: Buffer;
  extension: string;
}): Promise<ImageFileRecord> {
  const folder = toOutputFolder(params.projectId);
  await fs.mkdir(folder, { recursive: true });

  const filename = `edit-${Date.now()}-${randomUUID().slice(0, 6)}.${params.extension}`;
  const diskPath = path.join(folder, filename);
  await fs.writeFile(diskPath, params.buffer);

  const filepath = `/uploads/studio/${params.projectId}/outputs/${filename}`;
  const mimetype = params.extension === "jpeg" ? "image/jpeg" : "image/png";
  const now = new Date();

  try {
    const repo = await getImageFileRepository();
    return await repo.createImageFile({
      filename,
      filepath,
      mimetype,
      size: params.buffer.length,
      tags: ["image-studio", "output"],
    });
  } catch {
    return {
      id: randomUUID(),
      filename,
      filepath,
      mimetype,
      size: params.buffer.length,
      width: null,
      height: null,
      tags: ["image-studio", "output"],
      createdAt: now.toISOString(),
      updatedAt: now.toISOString(),
    };
  }
}

async function POST_handler(req: NextRequest, _ctx: ApiHandlerContext): Promise<Response> {
  try {
    const body = (await req.json().catch(() => null)) as unknown;
    const parsed = runSchema.safeParse(body);
    if (!parsed.success) {
      return NextResponse.json({ error: "Invalid payload" }, { status: 400 });
    }

    const projectId = sanitizeProjectId(parsed.data.projectId);
    if (!projectId) throw badRequestError("Project id is required.");

    const assetPath = parsed.data.asset.filepath;
    if (!assetPath.startsWith(`/uploads/studio/${projectId}/`)) {
      throw badRequestError("Asset must belong to the current project.");
    }

    const diskPath = resolveAssetPath(assetPath);
    ensureWithinProject(diskPath, projectId);

    await fs.stat(diskPath).catch(() => {
      throw badRequestError("Asset file not found.");
    });

    const settings = parseImageStudioSettings(
      parsed.data.studioSettings ? JSON.stringify(parsed.data.studioSettings) : null
    );

    if (settings.targetAi.openai.api !== "images") {
      throw badRequestError("Image Studio run currently supports the Images API only.");
    }

    const apiKey =
      (await getSettingValue("openai_api_key")) ?? process.env.OPENAI_API_KEY ?? null;
    if (!apiKey) {
      throw configurationError("OpenAI API key is missing. Set it in /admin/settings/ai.");
    }

    const client = new OpenAI({ apiKey });

    const format = settings.targetAi.openai.image.format ?? "png";
    const overrides =
      settings.targetAi.openai.advanced_overrides && typeof settings.targetAi.openai.advanced_overrides === "object"
        ? settings.targetAi.openai.advanced_overrides
        : null;

    let polygons: Array<Array<{ x: number; y: number }>> = [];
    let invert = false;
    let feather = 0;
    if (parsed.data.mask) {
      if (parsed.data.mask.type === "polygon") {
        if (parsed.data.mask.closed && parsed.data.mask.points.length >= 3) {
          polygons = [parsed.data.mask.points];
        }
      } else {
        polygons = parsed.data.mask.polygons;
        invert = Boolean(parsed.data.mask.invert);
        feather = typeof parsed.data.mask.feather === "number" ? parsed.data.mask.feather : 0;
      }
    }
    const mask =
      polygons.length > 0
        ? await buildMaskBuffer({ imagePath: diskPath, polygons, invert, feather })
        : null;

    const payload: OpenAI.Images.ImageEditParamsNonStreaming = {
      model: settings.targetAi.openai.model,
      prompt: parsed.data.prompt,
      image: createReadStream(diskPath),
      output_format: format,
      response_format: "b64_json",
    };

    if (typeof settings.targetAi.openai.image.n === "number") {
      payload.n = settings.targetAi.openai.image.n;
    }
    const size = coerceImageSize(settings.targetAi.openai.image.size ?? null);
    if (size) {
      payload.size = size;
    }
    if (settings.targetAi.openai.image.quality) {
      payload.quality = settings.targetAi.openai.image.quality;
    }
    const background = mapBackground(settings.targetAi.openai.image.background);
    if (background) {
      payload.background = background;
    }
    if (settings.targetAi.openai.user) {
      payload.user = settings.targetAi.openai.user;
    }

    if (mask) {
      payload.mask = await toFile(mask, "mask.png");
    }

    if (overrides) {
      const { image, mask: overrideMask, prompt, ...rest } =
        overrides as Partial<OpenAI.Images.ImageEditParamsNonStreaming>;
      void image;
      void overrideMask;
      void prompt;
      const target = payload as unknown as Record<string, unknown>;
      Object.entries(rest).forEach(([key, value]) => {
        if (value !== undefined) {
          target[key] = value as unknown;
        }
      });
    }

    const response = await client.images.edit(payload);
    const images = response.data ?? [];
    if (images.length === 0) {
      throw operationFailedError("Image API returned no images.");
    }

    const outputs: ImageFileRecord[] = [];
    for (const img of images) {
      if (!img.b64_json) {
        throw operationFailedError("Image API did not return base64 data.");
      }
      const buffer = Buffer.from(img.b64_json, "base64");
      const record = await createImageRecord({
        projectId,
        buffer,
        extension: format === "jpeg" ? "jpeg" : "png",
      });
      outputs.push(record);
    }

    return NextResponse.json({ outputs });
  } catch (error) {
    return createErrorResponse(error, {
      request: req,
      source: "image-studio.run.POST",
      fallbackMessage: "Failed to run Image Studio",
    });
  }
}

export const POST = apiHandler(async (req: NextRequest, ctx: ApiHandlerContext): Promise<Response> => POST_handler(req, ctx), {
  source: "image-studio.run.POST",
});

export const runtime = "nodejs";

import OpenAI from "openai";
import { NextRequest, NextResponse } from "next/server";
import { z } from "zod";

import { auth } from "@/features/auth/server";
import { getSettingValue } from "@/features/products/services/aiDescriptionService";
import { apiHandler } from "@/shared/lib/api/api-handler";
import { parseJsonBody } from "@/shared/lib/api/parse-json";
import { createErrorResponse } from "@/shared/lib/api/handle-api-error";
import { authError, configurationError } from "@/shared/errors/app-error";
import type { ApiHandlerContext } from "@/shared/types/api";
import {
  IMAGE_STUDIO_SETTINGS_KEY,
  parseImageStudioSettings,
} from "@/features/ai/image-studio/utils/studio-settings";

const uiControlEnum = z.enum([
  "auto",
  "checkbox",
  "buttons",
  "select",
  "slider",
  "number",
  "text",
  "textarea",
  "json",
  "rgb",
  "tuple2",
]);

const paramSpecSchema = z
  .object({
    kind: z.string().optional(),
    min: z.number().optional(),
    max: z.number().optional(),
    enumOptions: z.array(z.string()).optional(),
  })
  .partial();

const payloadSchema = z.object({
  prompt: z.string().trim().min(1),
  params: z.array(
    z.object({
      path: z.string().trim().min(1),
      value: z.unknown(),
      spec: paramSpecSchema.nullable().optional(),
    })
  ),
  mode: z.enum(["heuristic", "ai", "both"]).optional().default("ai"),
});

const responseSchema = z.object({
  suggestions: z.array(
    z.object({
      path: z.string().trim().min(1),
      control: uiControlEnum,
      reason: z.string().trim().min(1).nullable().optional(),
      confidence: z.number().min(0).max(1).optional(),
    })
  ),
});

async function POST_handler(req: NextRequest, _ctx: ApiHandlerContext): Promise<Response> {
  try {
    const session = await auth();
    const hasAccess =
      session?.user?.isElevated ||
      session?.user?.permissions?.includes("ai_paths.manage");
    if (!hasAccess) throw authError("Unauthorized.");

    const parsed = await parseJsonBody(req, payloadSchema, { logPrefix: "image-studio.ui-extractor.POST" });
    if (!parsed.ok) return parsed.response;

    const apiKey = (await getSettingValue("openai_api_key")) ?? process.env.OPENAI_API_KEY ?? null;
    if (!apiKey) {
      throw configurationError("OpenAI API key is missing. Set it in /admin/settings/ai.");
    }

    const settingsRaw = await getSettingValue(IMAGE_STUDIO_SETTINGS_KEY);
    const settings = parseImageStudioSettings(settingsRaw);
    const model = settings.uiExtractor.model || (await getSettingValue("openai_model")) || "gpt-4o-mini";
    const temperature = settings.uiExtractor.temperature ?? 0.2;
    const max_output_tokens = settings.uiExtractor.max_output_tokens ?? 800;

    const client = new OpenAI({ apiKey });

    const systemPrompt = [
      "You map prompt parameters to UI controls.",
      "Return ONLY JSON matching: { \"suggestions\": [{ path, control, reason?, confidence? }] }.",
      "Controls must be one of: auto, checkbox, buttons, select, slider, number, text, textarea, json, rgb, tuple2.",
      "Prefer: booleans->checkbox, enums->buttons/select, 0..1 or bounded numbers->slider,",
      "short strings->text, long/multiline strings->textarea, arrays/objects->json, RGB arrays->rgb, 2-number arrays->tuple2.",
      "Use confidence 0..1 (optional).",
    ].join("\n");

    const userPrompt = [
      "Prompt:",
      parsed.data.prompt,
      "",
      "Parameters (path, value, spec):",
      JSON.stringify(parsed.data.params, null, 2),
    ].join("\n");

    const response = await client.chat.completions.create({
      model,
      temperature,
      max_tokens: max_output_tokens,
      messages: [
        { role: "system", content: systemPrompt },
        { role: "user", content: userPrompt },
      ],
    });

    const raw = response.choices[0]?.message?.content ?? "";
    let json: unknown;
    try {
      json = JSON.parse(raw);
    } catch {
      throw new Error("Model did not return valid JSON.");
    }

    const validated = responseSchema.safeParse(json);
    if (!validated.success) {
      throw new Error("Invalid UI extractor response shape.");
    }

    return NextResponse.json({
      suggestions: validated.data.suggestions.map((s) => ({
        path: s.path,
        valuePreview: "",
        control: s.control,
        options: [s.control],
        confidence: s.confidence ?? 0.6,
        reason: s.reason ?? null,
        source: "ai",
      })),
    });
  } catch (error) {
    return createErrorResponse(error, {
      request: req,
      source: "image-studio.ui-extractor.POST",
      fallbackMessage: "Failed to extract UI suggestions",
    });
  }
}

export const POST = apiHandler(
  async (req: NextRequest, ctx: ApiHandlerContext): Promise<Response> => POST_handler(req, ctx),
  { source: "image-studio.ui-extractor.POST" }
);

import { NextRequest, NextResponse } from "next/server";
import { getUserPreferences, updateUserPreferences, type UserPreferencesData } from "@/features/auth/server";
import { z } from "zod";
import { createErrorResponse } from "@/shared/lib/api/handle-api-error";
import { apiHandler } from "@/shared/lib/api/api-handler";
import type { ApiHandlerContext } from "@/shared/types/api";
import { auth } from "@/features/auth/server";
import { isAbortError } from "@/features/ai/chatbot/utils";

export const runtime = "nodejs";

// For now, we'll use a hardcoded user ID
// In a real app, this would come from the session
const DEFAULT_USER_ID = "default-user";
const isDatabaseConfigured = Boolean(process.env.MONGODB_URI);

const updatePreferencesSchema = z.object({
  productListNameLocale: z.enum(["name_en", "name_pl", "name_de"]).optional().nullable(),
  productListCatalogFilter: z.string().optional().nullable(),
  productListCurrencyCode: z.string().optional().nullable(),
  productListPageSize: z.number().int().min(10).max(200).optional().nullable(),
  productListThumbnailSource: z.enum(["file", "link", "base64"]).optional().nullable(),
  aiPathsActivePathId: z.string().optional().nullable(),
  aiPathsExpandedGroups: z.array(z.string()).optional().nullable(),
  aiPathsPaletteCollapsed: z.boolean().optional().nullable(),
  aiPathsPathIndex: z.array(z["unknown"]()).optional().nullable(),
  aiPathsPathConfigs: z.union([z.record(z.string(), z["unknown"]()), z.string()]).optional().nullable(),
  adminMenuCollapsed: z.boolean().optional().nullable(),
  adminMenuFavorites: z.array(z.string()).optional().nullable(),
  adminMenuSectionColors: z.record(z.string(), z.string()).optional().nullable(),
  adminMenuCustomEnabled: z.boolean().optional().nullable(),
  adminMenuCustomNav: z.array(z.unknown()).optional().nullable(),
  cmsLastPageId: z.string().optional().nullable(),
  cmsActiveDomainId: z.string().optional().nullable(),
  cmsThemeOpenSections: z.array(z.string()).optional().nullable(),
  cmsThemeLogoWidth: z.number().int().min(50).max(300).optional().nullable(),
  cmsThemeLogoUrl: z.string().optional().nullable(),
  cmsPreviewEnabled: z.boolean().optional().nullable(),
});

/**
 * GET /api/user/preferences
 * Get current user preferences
 */
async function GET_handler(_req: NextRequest, _ctx: ApiHandlerContext): Promise<Response> {
  let userId = DEFAULT_USER_ID;
  try {
    const session = await auth();
    userId = session?.user?.id ?? DEFAULT_USER_ID;
    if (!isDatabaseConfigured) {
      return NextResponse.json({
        productListNameLocale: "name_en",
        productListCatalogFilter: "all",
        productListCurrencyCode: "PLN",
        productListPageSize: 12,
        productListThumbnailSource: "file",
        aiPathsActivePathId: null,
        aiPathsExpandedGroups: ["Triggers"],
        aiPathsPaletteCollapsed: false,
        aiPathsPathIndex: null,
        aiPathsPathConfigs: null,
        adminMenuCollapsed: false,
        adminMenuFavorites: [],
        adminMenuSectionColors: {},
        adminMenuCustomEnabled: false,
        adminMenuCustomNav: [],
        cmsLastPageId: null,
        cmsActiveDomainId: null,
        cmsThemeOpenSections: [],
        cmsThemeLogoWidth: null,
        cmsThemeLogoUrl: null,
        cmsPreviewEnabled: false,
      });
    }
    const preferences = await getUserPreferences(userId);
    return NextResponse.json(preferences);
  } catch (error) {
    return createErrorResponse(error, {
      source: "user.preferences.GET",
      fallbackMessage: "Failed to fetch preferences",
    });
  }
}

/**
 * PATCH /api/user/preferences
 * Update user preferences
 */
async function PATCH_handler(req: NextRequest, _ctx: ApiHandlerContext): Promise<Response> {
  let data: Partial<UserPreferencesData> = {};
  let userId = DEFAULT_USER_ID;
  try {
    const session = await auth();
    userId = session?.user?.id ?? DEFAULT_USER_ID;
    const rawBody = await req.text();
    let body: unknown = {};
    if (rawBody) {
      try {
        body = JSON.parse(rawBody);
      } catch (parseError) {
        if (parseError instanceof SyntaxError) {
          body = {};
        } else {
          throw parseError;
        }
      }
    }
    const parsed = updatePreferencesSchema.parse(body);

    // Type assertion to handle exactOptionalPropertyTypes
    const partial: Record<string, unknown> = {};
    if (parsed.productListNameLocale !== undefined) partial.productListNameLocale = parsed.productListNameLocale;
    if (parsed.productListCatalogFilter !== undefined) partial.productListCatalogFilter = parsed.productListCatalogFilter;
    if (parsed.productListCurrencyCode !== undefined) partial.productListCurrencyCode = parsed.productListCurrencyCode;
    if (parsed.productListPageSize !== undefined) partial.productListPageSize = parsed.productListPageSize;
    if (parsed.productListThumbnailSource !== undefined) partial.productListThumbnailSource = parsed.productListThumbnailSource;
    if (parsed.aiPathsActivePathId !== undefined) partial.aiPathsActivePathId = parsed.aiPathsActivePathId;
    if (parsed.aiPathsExpandedGroups !== undefined) partial.aiPathsExpandedGroups = parsed.aiPathsExpandedGroups ?? [];
    if (parsed.aiPathsPaletteCollapsed !== undefined) partial.aiPathsPaletteCollapsed = parsed.aiPathsPaletteCollapsed;
    if (parsed.aiPathsPathIndex !== undefined) partial.aiPathsPathIndex = parsed.aiPathsPathIndex ?? null;
    if (parsed.aiPathsPathConfigs !== undefined) partial.aiPathsPathConfigs = parsed.aiPathsPathConfigs ?? null;
    if (parsed.adminMenuCollapsed !== undefined) partial.adminMenuCollapsed = parsed.adminMenuCollapsed;
    if (parsed.adminMenuFavorites !== undefined) partial.adminMenuFavorites = parsed.adminMenuFavorites ?? [];
    if (parsed.adminMenuSectionColors !== undefined) partial.adminMenuSectionColors = parsed.adminMenuSectionColors ?? {};
    if (parsed.adminMenuCustomEnabled !== undefined) partial.adminMenuCustomEnabled = parsed.adminMenuCustomEnabled;
    if (parsed.adminMenuCustomNav !== undefined) partial.adminMenuCustomNav = parsed.adminMenuCustomNav ?? [];
    if (parsed.cmsLastPageId !== undefined) partial.cmsLastPageId = parsed.cmsLastPageId;
    if (parsed.cmsActiveDomainId !== undefined) partial.cmsActiveDomainId = parsed.cmsActiveDomainId;
    if (parsed.cmsThemeOpenSections !== undefined) partial.cmsThemeOpenSections = parsed.cmsThemeOpenSections ?? [];
    if (parsed.cmsThemeLogoWidth !== undefined) partial.cmsThemeLogoWidth = parsed.cmsThemeLogoWidth;
    if (parsed.cmsThemeLogoUrl !== undefined) partial.cmsThemeLogoUrl = parsed.cmsThemeLogoUrl;
    if (parsed.cmsPreviewEnabled !== undefined) partial.cmsPreviewEnabled = parsed.cmsPreviewEnabled;
    data = partial as Partial<UserPreferencesData>;

    if (!isDatabaseConfigured) {
      return NextResponse.json({
        id: "mock",
        userId,
        ...data,
        createdAt: new Date(),
        updatedAt: new Date(),
      });
    }

    const updated = await updateUserPreferences(userId, data);
    return NextResponse.json(updated);
  } catch (error) {
    const isAbort =
      req.signal.aborted ||
      isAbortError(error) ||
      (error instanceof Error && (error as { code?: string }).code === "ECONNRESET");
    if (isAbort) {
      return new NextResponse(null, { status: 204 });
    }
    return createErrorResponse(error, {
      request: req,
      source: "user.preferences.PATCH",
      fallbackMessage: "Failed to update preferences",
    });
  }
}

export const GET = apiHandler(
  async (req: NextRequest, ctx: ApiHandlerContext): Promise<Response> => GET_handler(req, ctx),
 { source: "user.preferences.GET" });
export const PATCH = apiHandler(
  async (req: NextRequest, ctx: ApiHandlerContext): Promise<Response> => PATCH_handler(req, ctx),
 { source: "user.preferences.PATCH" });
// POST handler for sendBeacon (used during page unload to save AI Paths settings)
export const POST = apiHandler(
  async (req: NextRequest, ctx: ApiHandlerContext): Promise<Response> => PATCH_handler(req, ctx),
 { source: "user.preferences.POST" });

