"use client";

import React, { useCallback, useMemo, useState } from "react";
import Link from "next/link";
import { ArrowDown, ArrowUp, ChevronLeft, ChevronRight, Plus, Star, Trash2 } from "lucide-react";

import { Button, Checkbox, Input, Label, SearchInput, SectionHeader, SectionPanel, Select, SelectContent, SelectItem, SelectTrigger, SelectValue, Switch, useToast } from "@/shared/ui";
import { cn } from "@/shared/utils";
import { useUserPreferences, useUpdateUserPreferencesMutation } from "@/features/auth/hooks/useUserPreferences";
import {
  ADMIN_MENU_COLOR_MAP,
  ADMIN_MENU_COLORS,
  AdminMenuCustomNode,
  AdminNavLeaf,
  buildAdminMenuFromCustomNav,
  buildAdminNav,
  adminNavToCustomNav,
  flattenAdminNav,
  getAdminMenuSections,
  normalizeAdminMenuCustomNav,
  type NavItem,
} from "@/features/admin/components/Menu";

const normalize = (value: string): string =>
  value.toLowerCase().replace(/[_/\\-]+/g, " ").replace(/\s+/g, " ").trim();

type ColorOption = (typeof ADMIN_MENU_COLORS)[number];

type AdminNavNodeEntry = {
  id: string;
  label: string;
  href?: string;
  parents: string[];
  item: NavItem;
};

type FlattenedCustomNode = {
  node: AdminMenuCustomNode;
  path: number[];
  depth: number;
  index: number;
  siblingCount: number;
};

const createCustomId = (): string =>
  `custom-${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`;

const createCustomNode = (kind: "link" | "group"): AdminMenuCustomNode => ({
  id: createCustomId(),
  label: kind === "group" ? "New Group" : "New Link",
  ...(kind === "link" ? { href: "/admin" } : {}),
  ...(kind === "group" ? { children: [] } : {}),
});

const cloneCustomNav = (items: AdminMenuCustomNode[]): AdminMenuCustomNode[] => {
  if (typeof globalThis.structuredClone === "function") {
    return globalThis.structuredClone(items);
  }
  return JSON.parse(JSON.stringify(items)) as AdminMenuCustomNode[];
};

const flattenCustomNav = (
  items: AdminMenuCustomNode[],
  depth: number = 0,
  pathPrefix: number[] = []
): FlattenedCustomNode[] => {
  const entries: FlattenedCustomNode[] = [];
  items.forEach((node: AdminMenuCustomNode, index: number) => {
    const path = [...pathPrefix, index];
    entries.push({ node, path, depth, index, siblingCount: items.length });
    if (node.children && node.children.length > 0) {
      entries.push(...flattenCustomNav(node.children, depth + 1, path));
    }
  });
  return entries;
};

const flattenAdminNavNodes = (items: NavItem[], parents: string[] = []): AdminNavNodeEntry[] => {
  const entries: AdminNavNodeEntry[] = [];
  items.forEach((item: NavItem) => {
    entries.push({ id: item.id, label: item.label, href: item.href, parents, item });
    if (item.children && item.children.length > 0) {
      entries.push(...flattenAdminNavNodes(item.children, [...parents, item.label]));
    }
  });
  return entries;
};

const collectCustomIds = (
  items: AdminMenuCustomNode[],
  ids: Set<string> = new Set<string>()
): Set<string> => {
  items.forEach((node: AdminMenuCustomNode) => {
    ids.add(node.id);
    if (node.children && node.children.length > 0) {
      collectCustomIds(node.children, ids);
    }
  });
  return ids;
};

const getNodeAtPath = (items: AdminMenuCustomNode[], path: number[]): AdminMenuCustomNode | null => {
  let current: AdminMenuCustomNode | null = null;
  let cursor: AdminMenuCustomNode[] = items;
  for (const index of path) {
    current = cursor[index] ?? null;
    if (!current) return null;
    cursor = current.children ?? [];
  }
  return current;
};

const getParentAtPath = (
  items: AdminMenuCustomNode[],
  path: number[]
): { parent: AdminMenuCustomNode[]; index: number } | null => {
  if (path.length === 0) return null;
  const parentPath = path.slice(0, -1);
  const parentNode = parentPath.length ? getNodeAtPath(items, parentPath) : null;
  const parent = parentPath.length ? parentNode?.children ?? null : items;
  if (!parent) return null;
  return { parent, index: path[path.length - 1] };
};

const stripUsedIds = (
  node: AdminMenuCustomNode,
  usedIds: Set<string>
): AdminMenuCustomNode | null => {
  if (usedIds.has(node.id)) return null;
  usedIds.add(node.id);
  const children = node.children
    ? node.children
        .map((child: AdminMenuCustomNode) => stripUsedIds(child, usedIds))
        .filter((child: AdminMenuCustomNode | null): child is AdminMenuCustomNode => Boolean(child))
    : undefined;
  return {
    ...node,
    ...(children ? { children } : {}),
  };
};

export function AdminMenuSettingsPage(): React.JSX.Element {
  const { data: preferences } = useUserPreferences();
  const updatePreferences = useUpdateUserPreferencesMutation();
  const { toast } = useToast();

  const [favorites, setFavorites] = useState<string[]>([]);
  const [sectionColors, setSectionColors] = useState<Record<string, string>>({});
  const [query, setQuery] = useState("");
  const [customEnabled, setCustomEnabled] = useState(false);
  const [customNav, setCustomNav] = useState<AdminMenuCustomNode[]>([]);
  const [libraryQuery, setLibraryQuery] = useState("");

  const noopClick = useCallback((event: React.MouseEvent<HTMLAnchorElement>): void => {
    event.preventDefault();
  }, []);

  const baseNav = useMemo(
    () =>
      buildAdminNav({
        onOpenChat: noopClick,
        onCreatePageClick: () => {},
      }),
    [noopClick]
  );

  const defaultCustomNav = useMemo(() => adminNavToCustomNav(baseNav), [baseNav]);
  const normalizedPreferenceCustomNav = useMemo(() => {
    const normalized = normalizeAdminMenuCustomNav(preferences?.adminMenuCustomNav);
    return normalized.length > 0 ? normalized : defaultCustomNav;
  }, [defaultCustomNav, preferences?.adminMenuCustomNav]);
  const normalizedCustomNav = useMemo(() => {
    const normalized = normalizeAdminMenuCustomNav(customNav);
    return normalized.length > 0 ? normalized : defaultCustomNav;
  }, [customNav, defaultCustomNav]);

  // Derived state for initialization
  const [prevPrefs, setPrevPrefs] = useState<unknown>(null);
  if (preferences && preferences !== prevPrefs && Object.keys(preferences).length > 0) {
    setPrevPrefs(preferences);
    setFavorites(Array.isArray(preferences.adminMenuFavorites) ? preferences.adminMenuFavorites : []);
    setSectionColors(
      preferences.adminMenuSectionColors && typeof preferences.adminMenuSectionColors === "object"
        ? preferences.adminMenuSectionColors
        : {}
    );
    setCustomEnabled(Boolean(preferences.adminMenuCustomEnabled));
    setCustomNav(normalizedPreferenceCustomNav);
  }

  const menuNav = useMemo(
    () => (customEnabled ? buildAdminMenuFromCustomNav(normalizedCustomNav, baseNav) : baseNav),
    [baseNav, customEnabled, normalizedCustomNav]
  );

  const sections = useMemo(() => getAdminMenuSections(menuNav), [menuNav]);
  const flattened = useMemo(() => flattenAdminNav(menuNav), [menuNav]);
  const favoritesSet = useMemo(() => new Set(favorites), [favorites]);
  const favoritesList = useMemo(
    () => favorites.map((id: string) => flattened.find((item: AdminNavLeaf) => item.id === id)).filter(Boolean),
    [favorites, flattened]
  );

  const filteredItems = useMemo(() => {
    const normalized = normalize(query);
    const items = flattened.filter((item: AdminNavLeaf) =>
      normalize([item.label, item.href ?? "", ...(item.keywords ?? []), ...item.parents].join(" "))
        .includes(normalized)
    );
    return items.sort((a: AdminNavLeaf, b: AdminNavLeaf) => a.label.localeCompare(b.label));
  }, [flattened, query]);

  const flattenedCustomNav = useMemo(() => flattenCustomNav(customNav), [customNav]);
  const libraryItems = useMemo(() => flattenAdminNavNodes(baseNav), [baseNav]);
  const libraryItemMap = useMemo(
    () => new Map(libraryItems.map((item: AdminNavNodeEntry) => [item.id, item])),
    [libraryItems]
  );
  const customIds = useMemo(() => collectCustomIds(customNav), [customNav]);
  const filteredLibraryItems = useMemo(() => {
    const normalized = normalize(libraryQuery);
    const items = libraryItems.filter((item: AdminNavNodeEntry) =>
      normalize([item.label, item.href ?? "", ...item.parents].join(" ")).includes(normalized)
    );
    return items.sort((a: AdminNavNodeEntry, b: AdminNavNodeEntry) => a.label.localeCompare(b.label));
  }, [libraryItems, libraryQuery]);

  const defaultPayload = useMemo(
    () =>
      JSON.stringify({
        favorites: [],
        sectionColors: {},
        customEnabled: false,
        customNav: defaultCustomNav,
      }),
    [defaultCustomNav]
  );

  const baseline = useMemo(
    () =>
      JSON.stringify({
        favorites: Array.isArray(preferences?.adminMenuFavorites) ? preferences?.adminMenuFavorites : [],
        sectionColors: preferences?.adminMenuSectionColors ?? {},
        customEnabled: Boolean(preferences?.adminMenuCustomEnabled),
        customNav: normalizedPreferenceCustomNav,
      }),
    [normalizedPreferenceCustomNav, preferences?.adminMenuCustomEnabled, preferences?.adminMenuFavorites, preferences?.adminMenuSectionColors]
  );

  const currentPayload = useMemo(
    () =>
      JSON.stringify({
        favorites,
        sectionColors,
        customEnabled,
        customNav: normalizedCustomNav,
      }),
    [customEnabled, favorites, normalizedCustomNav, sectionColors]
  );

  const isDirty = baseline !== currentPayload;
  const isDefaultState = currentPayload === defaultPayload;

  const handleToggleFavorite = (id: string, checked: boolean): void => {
    setFavorites((prev: string[]) => {
      if (checked) {
        if (prev.includes(id)) return prev;
        return [...prev, id];
      }
      return prev.filter((fav: string) => fav !== id);
    });
  };

  const moveFavorite = (id: string, direction: "up" | "down"): void => {
    setFavorites((prev: string[]) => {
      const index = prev.indexOf(id);
      if (index === -1) return prev;
      const next = [...prev];
      const targetIndex = direction === "up" ? index - 1 : index + 1;
      if (targetIndex < 0 || targetIndex >= next.length) return prev;
      const [removed] = next.splice(index, 1);
      if (!removed) return prev;
      next.splice(targetIndex, 0, removed);
      return next;
    });
  };

  const updateSectionColor = (sectionId: string, value: string): void => {
    setSectionColors((prev: Record<string, string>) => {
      const next = { ...prev };
      if (value === "none") {
        delete next[sectionId];
        return next;
      }
      next[sectionId] = value;
      return next;
    });
  };

  const updateCustomLabel = (path: number[], value: string): void => {
    setCustomNav((prev: AdminMenuCustomNode[]) => {
      const next = cloneCustomNav(prev);
      const info = getParentAtPath(next, path);
      if (!info || !info.parent[info.index]) return prev;
      info.parent[info.index].label = value;
      return next;
    });
  };

  const updateCustomHref = (path: number[], value: string): void => {
    setCustomNav((prev: AdminMenuCustomNode[]) => {
      const next = cloneCustomNav(prev);
      const info = getParentAtPath(next, path);
      if (!info || !info.parent[info.index]) return prev;
      if (value.trim().length === 0) {
        delete info.parent[info.index].href;
      } else {
        info.parent[info.index].href = value;
      }
      return next;
    });
  };

  const addCustomNodeAt = (kind: "link" | "group", parentPath?: number[]): void => {
    setCustomNav((prev: AdminMenuCustomNode[]) => {
      const next = cloneCustomNav(prev);
      const node = createCustomNode(kind);
      if (!parentPath || parentPath.length === 0) {
        next.push(node);
        return next;
      }
      const parentNode = getNodeAtPath(next, parentPath);
      if (!parentNode) return prev;
      if (!parentNode.children) parentNode.children = [];
      parentNode.children.push(node);
      return next;
    });
  };

  const addBuiltInNode = (entry: AdminNavNodeEntry): void => {
    setCustomNav((prev: AdminMenuCustomNode[]) => {
      const next = cloneCustomNav(prev);
      const usedIds = collectCustomIds(next);
      const [node] = adminNavToCustomNav([entry.item]);
      if (!node) return prev;
      const cleaned = stripUsedIds(node, usedIds);
      if (!cleaned) return prev;
      next.push(cleaned);
      return next;
    });
  };

  const removeCustomNode = (path: number[]): void => {
    setCustomNav((prev) => {
      const next = cloneCustomNav(prev);
      const info = getParentAtPath(next, path);
      if (!info) return prev;
      info.parent.splice(info.index, 1);
      return next;
    });
  };

  const moveCustomNode = (path: number[], direction: "up" | "down"): void => {
    setCustomNav((prev) => {
      const next = cloneCustomNav(prev);
      const info = getParentAtPath(next, path);
      if (!info) return prev;
      const targetIndex = direction === "up" ? info.index - 1 : info.index + 1;
      if (targetIndex < 0 || targetIndex >= info.parent.length) return prev;
      const [node] = info.parent.splice(info.index, 1);
      if (!node) return prev;
      info.parent.splice(targetIndex, 0, node);
      return next;
    });
  };

  const indentCustomNode = (path: number[]): void => {
    setCustomNav((prev) => {
      const next = cloneCustomNav(prev);
      const info = getParentAtPath(next, path);
      if (!info || info.index === 0) return prev;
      const [node] = info.parent.splice(info.index, 1);
      const newParent = info.parent[info.index - 1];
      if (!newParent || !node) return prev;
      if (!newParent.children) newParent.children = [];
      newParent.children.push(node);
      return next;
    });
  };

  const outdentCustomNode = (path: number[]): void => {
    if (path.length < 2) return;
    setCustomNav((prev) => {
      const next = cloneCustomNav(prev);
      const info = getParentAtPath(next, path);
      if (!info) return prev;
      const parentPath = path.slice(0, -1);
      const parentInfo = getParentAtPath(next, parentPath);
      if (!parentInfo) return prev;
      const [node] = info.parent.splice(info.index, 1);
      if (!node) return prev;
      parentInfo.parent.splice(parentInfo.index + 1, 0, node);
      return next;
    });
  };

  const handleSave = async (): Promise<void> => {
    try {
      const validFavorites = favorites.filter((id: string) => flattened.some((item: AdminNavLeaf) => item.id === id));
      const sectionIds = new Set(sections.map((section) => section.id));
      const validSectionColors = Object.fromEntries(
        Object.entries(sectionColors).filter(([sectionId]) => sectionIds.has(sectionId))
      );
      await updatePreferences.mutateAsync({
        adminMenuFavorites: validFavorites,
        adminMenuSectionColors: validSectionColors,
        adminMenuCustomEnabled: customEnabled,
        adminMenuCustomNav: normalizedCustomNav,
      });
      toast("Admin menu settings saved.", { variant: "success" });
    } catch (error) {
      toast(error instanceof Error ? error.message : "Failed to save admin menu settings.", { variant: "error" });
    }
  };

  const handleReset = (): void => {
    setFavorites([]);
    setSectionColors({});
    setCustomEnabled(false);
    setCustomNav(defaultCustomNav);
  };

  return (
    <div className="container mx-auto py-10">
      <SectionHeader
        title="Admin Menu"
        description="Pin favorites, color sections, and build a custom menu layout."
        eyebrow={(
          <Link href="/admin/settings" className="text-blue-300 hover:text-blue-200">
            ← Back to settings
          </Link>
        )}
        className="mb-8"
      />

      <div className="grid gap-6 lg:grid-cols-2">
        <SectionPanel className="p-6">
          <div className="flex items-center justify-between">
            <div>
              <h2 className="text-sm font-semibold text-white">Favorites</h2>
              <p className="mt-1 text-xs text-gray-400">Pin menu items to appear at the top.</p>
            </div>
            <Star className="size-4 text-amber-300" />
          </div>

          <div className="mt-4 space-y-3">
            {favoritesList.length === 0 ? (
              <p className="rounded-md border border-border bg-card/40 p-3 text-xs text-gray-400">
                No favorites yet. Select items below to pin them here.
              </p>
            ) : (
              <div className="space-y-2">
                {favoritesList.map((entry: AdminNavLeaf | undefined, index: number) => (
                  <div key={entry?.id} className="flex items-center justify-between rounded-md border border-border/60 bg-card/40 px-3 py-2">
                    <div className="min-w-0">
                      <div className="truncate text-sm text-white">{entry?.label}</div>
                      {entry?.parents?.length ? (
                        <div className="truncate text-[11px] text-gray-500">
                          {entry.parents.join(" / ")}
                        </div>
                      ) : null}
                    </div>
                    <div className="flex items-center gap-1">
                      <Button
                        type="button"
                        variant="outline"
                        size="sm"
                        className="h-7 w-7 p-0"
                        disabled={index === 0}
                        onClick={() => entry?.id && moveFavorite(entry.id, "up")}
                      >
                        <ArrowUp className="size-3" />
                      </Button>
                      <Button
                        type="button"
                        variant="outline"
                        size="sm"
                        className="h-7 w-7 p-0"
                        disabled={index === favoritesList.length - 1}
                        onClick={() => entry?.id && moveFavorite(entry.id, "down")}
                      >
                        <ArrowDown className="size-3" />
                      </Button>
                      <Button
                        type="button"
                        variant="outline"
                        size="sm"
                        className="h-7 px-2 text-[11px]"
                        onClick={() => entry?.id && handleToggleFavorite(entry.id, false)}
                      >
                        Remove
                      </Button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>

          <div className="mt-5">
            <Label className="text-xs text-gray-400">Add favorites</Label>
            <SearchInput
              value={query}
              onChange={(event: React.ChangeEvent<HTMLInputElement>) => setQuery(event.target.value)}
              placeholder="Search admin menu…"
              className="mt-2 h-9 bg-gray-900/40"
              onClear={() => setQuery("")}
            />
            <div className="mt-3 max-h-72 space-y-2 overflow-auto pr-2">
              {filteredItems.map((item: AdminNavLeaf) => (
                <label
                  key={item.id}
                  className={cn(
                    "flex cursor-pointer items-start gap-3 rounded-md border border-border/60 bg-card/30 px-3 py-2 transition hover:bg-card/50",
                    favoritesSet.has(item.id) && "border-amber-500/40 bg-amber-500/5"
                  )}
                >
                  <Checkbox
                    checked={favoritesSet.has(item.id)}
                    onCheckedChange={(checked: boolean | "indeterminate") => handleToggleFavorite(item.id, Boolean(checked))}
                  />
                  <div className="min-w-0">
                    <div className="truncate text-sm text-white">{item.label}</div>
                    <div className="truncate text-[11px] text-gray-500">
                      {item.parents.join(" / ")}
                    </div>
                    {item.href ? (
                      <div className="truncate text-[11px] text-gray-600">{item.href}</div>
                    ) : null}
                  </div>
                </label>
              ))}
            </div>
          </div>
        </SectionPanel>

        <SectionPanel className="p-6">
          <h2 className="text-sm font-semibold text-white">Section Colors</h2>
          <p className="mt-1 text-xs text-gray-400">Assign accents to top-level menu sections.</p>

          <div className="mt-4 space-y-4">
            {sections.map((section) => {
              const current = sectionColors[section.id] ?? "none";
              const colorStyle = current !== "none" ? ADMIN_MENU_COLOR_MAP[current] : null;
              return (
                <div key={section.id} className="flex items-center justify-between gap-3 rounded-md border border-border/60 bg-card/40 px-3 py-2">
                  <div className="flex items-center gap-2">
                    {colorStyle ? (
                      <span className={cn("h-2.5 w-2.5 rounded-full", colorStyle.dot)} />
                    ) : (
                      <span className="h-2.5 w-2.5 rounded-full border border-dashed border-gray-500" />
                    )}
                    <span className="text-sm text-gray-200">{section.label}</span>
                  </div>
                  <Select value={current} onValueChange={(value) => updateSectionColor(section.id, value)}>
                    <SelectTrigger className="h-8 w-[160px] border-border bg-gray-900/40 text-xs text-white">
                      <SelectValue placeholder="Select color" />
                    </SelectTrigger>
                    <SelectContent>
                      <SelectItem value="none">
                        <span className="text-xs text-gray-400">None</span>
                      </SelectItem>
                      {ADMIN_MENU_COLORS.map((option: ColorOption) => (
                        <SelectItem key={option.value} value={option.value}>
                          <div className="flex items-center gap-2">
                            <span className={cn("h-2.5 w-2.5 rounded-full", option.dot)} />
                            <span>{option.label}</span>
                          </div>
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
              );
            })}
          </div>
        </SectionPanel>
      </div>

      <SectionPanel className="mt-6 p-6">
        <div className="flex flex-wrap items-start justify-between gap-3">
          <div>
            <h2 className="text-sm font-semibold text-white">Menu Builder</h2>
            <p className="mt-1 text-xs text-gray-400">Create hierarchies, reorder items, and add custom links.</p>
          </div>
          <div className="flex items-center gap-2">
            <Label className="text-xs text-gray-400">Use custom layout</Label>
            <Switch checked={customEnabled} onCheckedChange={(checked) => setCustomEnabled(Boolean(checked))} />
          </div>
        </div>

        {!customEnabled ? (
          <div className="mt-3 rounded-md border border-border/60 bg-card/40 px-3 py-2 text-xs text-gray-400">
            Custom layout is disabled. Enable it to apply this menu structure.
          </div>
        ) : null}

        <div className="mt-4 flex flex-wrap items-center gap-2">
          <Button type="button" size="sm" onClick={() => addCustomNodeAt("link")}>
            <Plus className="mr-2 size-4" />
            Add link
          </Button>
          <Button type="button" variant="outline" size="sm" onClick={() => addCustomNodeAt("group")}>
            <Plus className="mr-2 size-4" />
            Add group
          </Button>
          <Button type="button" variant="outline" size="sm" onClick={() => setCustomNav(defaultCustomNav)}>
            Restore default layout
          </Button>
        </div>

        <div className="mt-4 grid gap-6 lg:grid-cols-[minmax(0,1fr)_360px]">
          <div>
            <h3 className="text-xs font-semibold uppercase tracking-wide text-gray-400">Layout</h3>
            {flattenedCustomNav.length === 0 ? (
              <p className="mt-3 rounded-md border border-border bg-card/40 p-3 text-xs text-gray-400">
                No items yet. Add links or groups to start building your menu.
              </p>
            ) : (
              <div className="mt-3 space-y-2">
                {flattenedCustomNav.map((entry: FlattenedCustomNode) => {
                  const { node, path, depth, index, siblingCount } = entry;
                  const baseEntry = libraryItemMap.get(node.id);
                  const isBuiltIn = Boolean(baseEntry);
                  const labelValue = node.label ?? baseEntry?.label ?? "Untitled";
                  const hrefValue = node.href ?? baseEntry?.href ?? "";
                  const canMoveUp = index > 0;
                  const canMoveDown = index < siblingCount - 1;
                  const canIndent = index > 0;
                  const canOutdent = path.length > 1;
                  return (
                    <div
                      key={node.id}
                      className="flex flex-wrap items-center gap-2 rounded-md border border-border/60 bg-card/30 px-3 py-2"
                    >
                      <div className="flex min-w-0 flex-1 flex-wrap items-center gap-2" style={{ paddingLeft: depth * 16 }}>
                        <div className="min-w-[160px] flex-1">
                          <Input
                            value={labelValue}
                            onChange={(event) => updateCustomLabel(path, event.target.value)}
                            placeholder="Label"
                            className="h-8 bg-gray-900/40 text-xs"
                            disabled={isBuiltIn}
                          />
                        </div>
                        <div className="min-w-[180px] flex-1">
                          <Input
                            value={hrefValue}
                            onChange={(event) => updateCustomHref(path, event.target.value)}
                            placeholder="/admin/..."
                            className="h-8 bg-gray-900/40 text-xs"
                            disabled={isBuiltIn}
                          />
                        </div>
                        <span
                          className={cn(
                            "rounded-full border px-2 py-0.5 text-[10px] uppercase tracking-wide",
                            isBuiltIn ? "border-blue-500/40 text-blue-200" : "border-emerald-500/40 text-emerald-200"
                          )}
                        >
                          {isBuiltIn ? "Built-in" : "Custom"}
                        </span>
                      </div>
                      <div className="flex items-center gap-1">
                        <Button
                          type="button"
                          variant="outline"
                          size="sm"
                          className="h-8 w-8 p-0"
                          disabled={!canMoveUp}
                          onClick={() => moveCustomNode(path, "up")}
                          title="Move up"
                        >
                          <ArrowUp className="size-3" />
                        </Button>
                        <Button
                          type="button"
                          variant="outline"
                          size="sm"
                          className="h-8 w-8 p-0"
                          disabled={!canMoveDown}
                          onClick={() => moveCustomNode(path, "down")}
                          title="Move down"
                        >
                          <ArrowDown className="size-3" />
                        </Button>
                        <Button
                          type="button"
                          variant="outline"
                          size="sm"
                          className="h-8 w-8 p-0"
                          disabled={!canIndent}
                          onClick={() => indentCustomNode(path)}
                          title="Indent"
                        >
                          <ChevronRight className="size-3" />
                        </Button>
                        <Button
                          type="button"
                          variant="outline"
                          size="sm"
                          className="h-8 w-8 p-0"
                          disabled={!canOutdent}
                          onClick={() => outdentCustomNode(path)}
                          title="Outdent"
                        >
                          <ChevronLeft className="size-3" />
                        </Button>
                        <Button
                          type="button"
                          variant="outline"
                          size="sm"
                          className="h-8 w-8 p-0 text-red-200 hover:text-red-100"
                          onClick={() => removeCustomNode(path)}
                          title="Remove"
                        >
                          <Trash2 className="size-3" />
                        </Button>
                      </div>
                    </div>
                  );
                })}
              </div>
            )}
          </div>

          <div>
            <h3 className="text-xs font-semibold uppercase tracking-wide text-gray-400">Add built-in items</h3>
            <SearchInput
              value={libraryQuery}
              onChange={(event: React.ChangeEvent<HTMLInputElement>) => setLibraryQuery(event.target.value)}
              placeholder="Search built-in menu…"
              className="mt-2 h-9 bg-gray-900/40"
              onClear={() => setLibraryQuery("")}
            />
            <div className="mt-3 max-h-80 space-y-2 overflow-auto pr-2">
              {filteredLibraryItems.length === 0 ? (
                <p className="rounded-md border border-border bg-card/40 p-3 text-xs text-gray-400">
                  No matching menu items.
                </p>
              ) : (
                filteredLibraryItems.map((entry: AdminNavNodeEntry) => {
                  const isAdded = customIds.has(entry.id);
                  return (
                    <div key={entry.id} className="flex items-center justify-between gap-2 rounded-md border border-border/60 bg-card/30 px-3 py-2">
                      <div className="min-w-0">
                        <div className="truncate text-sm text-white">{entry.label}</div>
                        {entry.parents.length ? (
                          <div className="truncate text-[11px] text-gray-500">{entry.parents.join(" / ")}</div>
                        ) : null}
                        <div className="truncate text-[11px] text-gray-600">{entry.href ?? "Group"}</div>
                      </div>
                      <Button
                        type="button"
                        variant="outline"
                        size="sm"
                        className="h-7 px-2 text-[11px]"
                        disabled={isAdded}
                        onClick={() => addBuiltInNode(entry)}
                      >
                        {isAdded ? "Added" : "Add"}
                      </Button>
                    </div>
                  );
                })
              )}
            </div>
          </div>
        </div>
      </SectionPanel>

      <div className="mt-6 flex flex-wrap gap-2">
        <Button
          type="button"
          variant="outline"
          size="sm"
          onClick={handleReset}
          disabled={isDefaultState}
        >
          Reset
        </Button>
        <Button
          type="button"
          size="sm"
          onClick={handleSave}
          disabled={!isDirty || updatePreferences.isPending}
        >
          {updatePreferences.isPending ? "Saving..." : "Save Settings"}
        </Button>
      </div>
    </div>
  );
}

"use client";
import React, { useCallback, useMemo, useState } from "react";
import { useToast } from "@/shared/ui";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { logClientError } from "@/features/observability";
import { useUpdateSetting } from "@/shared/hooks/use-settings";
import { dbApi, entityApi } from "@/features/ai/ai-paths/lib";
import { DOCS_DESCRIPTION_SNIPPET, DOCS_JOBS_SNIPPET, DOCS_OVERVIEW_SNIPPET, DOCS_WIRING_SNIPPET } from "./docs-snippets";
import { useAiPathsCanvasInteractions } from "./useAiPathsCanvasInteractions";
import { useAiPathsPersistence } from "./useAiPathsPersistence";
import { useAiPathsRunHistory } from "./useAiPathsRunHistory";
import { useAiPathsPresets } from "./useAiPathsPresets";
import { useAiPathsRuntime } from "./useAiPathsRuntime";
import type {
  AiNode,
  Edge,
  NodeConfig,
  NodeDefinition,
  ParserSampleState,
  PathConfig,
  PathDebugSnapshot,
  PathMeta,
  RuntimeState,
  UpdaterSampleState,
} from "@/features/ai/ai-paths/lib";
import {
  AI_PATHS_LAST_ERROR_KEY,
  DEFAULT_MODELS,
  PATH_INDEX_KEY,
  STORAGE_VERSION,
  createAiDescriptionPath,
  createDefaultPathConfig,
  createPathId,
  createPathMeta,
  initialEdges,
  initialNodes,
  normalizeNodes,
  palette,
  safeStringify,
  sanitizeEdges,
  TRIGGER_INPUT_PORTS,
  TRIGGER_OUTPUT_PORTS,
  triggers,
  triggerButtonsApi,
} from "@/features/ai/ai-paths/lib";
import {
  parseRuntimeState,
  serializePathConfigs,
} from "../AiPathsSettingsUtils";
import type { AiTriggerButtonRecord } from "@/shared/types/ai-trigger-buttons";

type AiPathsSettingsStateOptions = {
  activeTab: "canvas" | "paths" | "docs";
};

const AI_PATHS_SAMPLE_STALE_MS = 10_000;

// eslint-disable-next-line @typescript-eslint/explicit-function-return-type, @typescript-eslint/explicit-module-boundary-types
export function useAiPathsSettingsState({ activeTab }: AiPathsSettingsStateOptions) {
  const { toast } = useToast();
  const normalizeTriggerLabel = (value?: string | null): string =>
    value === "Product Modal - Context Grabber"
      ? "Product Modal - Context Filter"
      : value ?? (triggers[0] ?? "Product Modal - Context Filter");
  const [nodes, setNodes] = useState<AiNode[]>(initialNodes);
  const [edges, setEdges] = useState<Edge[]>(initialEdges);
  const [paths, setPaths] = useState<PathMeta[]>([]);
  const [pathConfigs, setPathConfigs] = useState<Record<string, PathConfig>>({});
  const [activePathId, setActivePathId] = useState<string | null>(null);
  const [isPathLocked, setIsPathLocked] = useState(false);
  const [isPathActive, setIsPathActive] = useState(true);
  const [selectedNodeId, setSelectedNodeId] = useState<string | null>(
    initialNodes[0]?.id ?? null
  );
  const [loading, setLoading] = useState(true);
  const [configOpen, setConfigOpen] = useState(false);
  const [simulationOpenNodeId, setSimulationOpenNodeId] = useState<string | null>(
    null
  );
  const [pathName, setPathName] = useState("AI Description Path");
  const [pathDescription, setPathDescription] = useState(
    "Visual analysis + description generation with structured updates."
  );
  const [activeTrigger, setActiveTrigger] = useState(triggers[0] ?? "");
  const [parserSamples, setParserSamples] = useState<Record<string, ParserSampleState>>(
    {}
  );
  const [updaterSamples, setUpdaterSamples] = useState<Record<string, UpdaterSampleState>>(
    {}
  );
  const [runtimeState, setRuntimeState] = useState<RuntimeState>({
    inputs: {},
    outputs: {},
  });
  const [pathDebugSnapshots, setPathDebugSnapshots] = useState<
    Record<string, PathDebugSnapshot>
  >({});
  const [lastRunAt, setLastRunAt] = useState<string | null>(null);
  const [lastError, setLastError] = useState<{
    message: string;
    time: string;
    pathId?: string | null;
  } | null>(null);

  const lastGraphModelPayload = useMemo(() => {
    for (let index = nodes.length - 1; index >= 0; index -= 1) {
      const node = nodes[index];
      if (!node || node.type !== "model") continue;
      const output = runtimeState.outputs[node.id] as
        | { debugPayload?: unknown }
        | undefined;
      if (output?.debugPayload) {
        return output.debugPayload;
      }
    }
    return null;
  }, [nodes, runtimeState.outputs]);
  const [loadNonce, setLoadNonce] = useState(0);
  const queryClient = useQueryClient();
  const updateSettingMutation = useUpdateSetting();

  const triggerButtonsQuery = useQuery({
    queryKey: ["ai-paths", "trigger-buttons"],
    queryFn: async (): Promise<AiTriggerButtonRecord[]> => {
      const result = await triggerButtonsApi.list();
      if (!result.ok) return [];
      return Array.isArray(result.data) ? result.data : [];
    },
    staleTime: 10_000,
  });

  const paletteWithTriggerButtons = useMemo<NodeDefinition[]>(() => {
          const buttons = triggerButtonsQuery.data ?? [];
          if (buttons.length === 0) return palette;

          const usedTitles = new Set<string>(palette.map((node: NodeDefinition) => node.title));
          const derived: NodeDefinition[] = [];
    buttons.forEach((button: AiTriggerButtonRecord) => {
      const baseTitle = `Trigger: ${button.name}`;
      const title = usedTitles.has(baseTitle)
        ? `${baseTitle} (${button.id.slice(0, 6)})`
        : baseTitle;
      usedTitles.add(title);
      derived.push({
        type: "trigger",
        title,
        description: `User trigger button (${button.id}).`,
        inputs: TRIGGER_INPUT_PORTS,
        outputs: TRIGGER_OUTPUT_PORTS,
        config: { trigger: { event: button.id } },
      });
    });

    return [...palette, ...derived];
  }, [triggerButtonsQuery.data]);

  // Parser sample fetching mutation
  const fetchParserSampleMutation = useMutation({
    mutationFn: async ({
      nodeId,
      entityType,
      entityId,
    }: {
      nodeId: string;
      entityType: string;
      entityId: string;
    }): Promise<{ nodeId: string; entityType: string; entityId: string; sample: Record<string, unknown> }> => {
      if (!entityId.trim()) {
        throw new Error("Enter an entity ID to load a sample.");
      }
      if (entityType === "custom") {
        throw new Error("Use pasted JSON for custom samples.");
      }
      const normalized = entityType.trim().toLowerCase();
      const resolvedType =
        normalized === "products" ? "product" : normalized === "notes" ? "note" : normalized;
      let sample: Record<string, unknown> | null = null;
      if (resolvedType === "product") {
        sample = await queryClient.fetchQuery({
          queryKey: ["products", entityId],
          queryFn: async () => {
            const result = await entityApi.getProduct(entityId);
            return result.ok ? result.data : null;
          },
          staleTime: AI_PATHS_SAMPLE_STALE_MS,
        });
      } else if (resolvedType === "note") {
        sample = await queryClient.fetchQuery({
          queryKey: ["notes", entityId],
          queryFn: async () => {
            const result = await entityApi.getNote(entityId);
            return result.ok ? result.data : null;
          },
          staleTime: AI_PATHS_SAMPLE_STALE_MS,
        });
      }
      if (!sample) {
        throw new Error("No sample found for that ID.");
      }
      return { nodeId, entityType, entityId, sample };
    },
    onSuccess: ({ nodeId, entityType, entityId, sample }: { nodeId: string; entityType: string; entityId: string; sample: unknown }): void => {
      setParserSamples((prev: Record<string, ParserSampleState>) => ({
        ...prev,
        [nodeId]: {
          entityType,
          entityId,
          json: JSON.stringify(sample, null, 2),
          mappingMode: prev[nodeId]?.mappingMode ?? "top",
          depth: prev[nodeId]?.depth ?? 2,
          keyStyle: prev[nodeId]?.keyStyle ?? "path",
          includeContainers: prev[nodeId]?.includeContainers ?? false,
        },
      }));
    },
    onError: (error: Error): void => {
      toast(error instanceof Error ? error.message : "Failed to fetch sample.", { variant: "error" });
    },
  });

  // Updater sample fetching mutation
  const fetchUpdaterSampleMutation = useMutation({
    mutationFn: async ({
      nodeId,
      entityType,
      entityId,
    }: {
      nodeId: string;
      entityType: string;
      entityId: string;
    }): Promise<{ nodeId: string; entityType: string; entityId: string; sample: unknown }> => {
      if (entityType === "custom") {
        throw new Error("Use pasted JSON for custom samples.");
      }
      let sample: unknown = null;
      let fetchedId = entityId;

      // If no entityId provided, fetch first document from collection
      if (!entityId.trim()) {
        const data = await queryClient.fetchQuery({
          queryKey: ["db-browse-sample", entityType],
          queryFn: async () => {
            const result = await dbApi.browse(entityType, { limit: 1 });
            if (!result.ok) return { documents: [] as Record<string, unknown>[] };
            return { documents: result.data.documents ?? [] };
          },
          staleTime: AI_PATHS_SAMPLE_STALE_MS,
        });
        const firstDoc = data.documents?.[0];
        if (firstDoc) {
          sample = firstDoc;
          const rawId = firstDoc._id ?? firstDoc.id;
          fetchedId = (rawId as { toString?: () => string })?.toString?.() ?? "";
        }
      } else {
        const normalized = entityType.toLowerCase();
        if (normalized === "product") {
          sample = await queryClient.fetchQuery({
            queryKey: ["products", entityId],
          queryFn: async () => {
            const result = await entityApi.getProduct(entityId);
            return result.ok ? result.data : null;
          },
          staleTime: AI_PATHS_SAMPLE_STALE_MS,
        });
      } else if (normalized === "note") {
        sample = await queryClient.fetchQuery({
          queryKey: ["notes", entityId],
          queryFn: async () => {
            const result = await entityApi.getNote(entityId);
            return result.ok ? result.data : null;
          },
          staleTime: AI_PATHS_SAMPLE_STALE_MS,
        });
      }
      }

      if (!sample) {
        throw new Error("No sample found.");
      }
      return { nodeId, entityType, entityId: fetchedId, sample };
    },
    onSuccess: ({ nodeId, entityType, entityId, sample }: { nodeId: string; entityType: string; entityId: string; sample: unknown }): void => {
      setUpdaterSamples((prev: Record<string, UpdaterSampleState>) => ({
        ...prev,
        [nodeId]: {
          entityType,
          entityId,
          json: JSON.stringify(sample, null, 2),
          depth: prev[nodeId]?.depth ?? 2,
          includeContainers: prev[nodeId]?.includeContainers ?? false,
        },
      }));
      toast("Sample fetched.", { variant: "success" });
    },
    onError: (error: Error): void => {
      toast(error instanceof Error ? error.message : "Failed to fetch sample.", { variant: "error" });
    },
  });

  // Derived loading states from mutations
  const parserSampleLoading = fetchParserSampleMutation.isPending;
  const updaterSampleLoading = fetchUpdaterSampleMutation.isPending;

  const persistLastError = useCallback(
    async (
      payload: { message: string; time: string; pathId?: string | null } | null
    ): Promise<void> => {
      try {
        await updateSettingMutation.mutateAsync({
          key: AI_PATHS_LAST_ERROR_KEY,
          value: payload ? JSON.stringify(payload) : "",
        });
      } catch (error: unknown) {
        console.warn("[AI Paths] Failed to persist last error.", error);
      }
    },
    [updateSettingMutation]
  );

  const reportAiPathsError = useCallback(
    (
      error: unknown,
      context: Record<string, unknown>,
      fallbackMessage?: string
    ): void => {
      const rawMessage = error instanceof Error ? error.message : safeStringify(error);
      const summary = (fallbackMessage ?? rawMessage).replace(/:$/, "");
      const logMessage = `[AI Paths] ${summary}`;
      const logError = new Error(logMessage);
      if (error instanceof Error && error.stack) {
        logError.stack = error.stack;
        logError.name = error.name;
      }
      console.error(fallbackMessage ?? "AI Paths error:", error);
      const payload = {
        message: summary,
        time: new Date().toISOString(),
        pathId: activePathId,
      };
      setLastError(payload);
      void persistLastError(payload);
      logClientError(logError, {
        context: {
          feature: "ai-paths",
          pathId: activePathId,
          pathName,
          tab: activeTab,
          nodeCount: nodes.length,
          edgeCount: edges.length,
          errorSummary: summary,
          rawMessage,
          ...context,
        },
      });
    },
    [activePathId, activeTab, edges.length, nodes.length, pathName, persistLastError]
  );

  const modelsQuery = useQuery<{ models?: string[] }>({
    queryKey: ["ai-paths-models"],
    queryFn: async (): Promise<{ models?: string[] }> => {
      const res = await fetch("/api/chatbot");
      if (!res.ok) {
        throw new Error("Failed to load models.");
      }
      return (await res.json()) as { models?: string[] };
    },
    staleTime: 1000 * 60 * 5,
  });

  const modelOptions = useMemo((): string[] => {
    const apiModels = modelsQuery.data?.models;
    const savedModels = nodes
      .filter((node: AiNode): boolean => node.type === "model")
      .map((node: AiNode): string | undefined => node.config?.model?.modelId)
      .filter((modelId: string | undefined): modelId is string => Boolean(modelId && modelId.trim()));
    return Array.from(
      new Set([
        ...DEFAULT_MODELS,
        ...(Array.isArray(apiModels) ? apiModels : []),
        ...savedModels,
      ])
    );
  }, [modelsQuery.data, nodes]);

  const pruneRuntimeInputs = useCallback(
    (state: RuntimeState, removedEdges: Edge[], remainingEdges: Edge[]): RuntimeState => {
      if (removedEdges.length === 0) return state;
      const remainingTargets = new Set<string>();
      remainingEdges.forEach((edge: Edge) => {
        if (!edge.toPort) return;
        remainingTargets.add(`${edge.to}:${edge.toPort}`);
      });

      const existingInputs = state.inputs ?? {};
      let nextInputs = existingInputs;
      let changed = false;

      removedEdges.forEach((edge: Edge) => {
        if (!edge.toPort) return;
        const targetKey = `${edge.to}:${edge.toPort}`;
        if (remainingTargets.has(targetKey)) return;
        const nodeInputs = (nextInputs?.[edge.to] ?? {}) as Record<string, unknown>;
        if (!(edge.toPort in nodeInputs)) return;
        if (!changed) {
          nextInputs = { ...existingInputs };
          changed = true;
        }
        const nextNodeInputs = { ...nodeInputs };
        delete nextNodeInputs[edge.toPort];
        if (Object.keys(nextNodeInputs).length === 0) {
          delete (nextInputs as Record<string, Record<string, unknown>>)[edge.to];
        } else {
          (nextInputs as Record<string, Record<string, unknown>>)[edge.to] = nextNodeInputs;
        }
      });

      if (!changed) return state;
      return { ...state, inputs: nextInputs };
    },
    []
  );

  const clearRuntimeInputsForEdges = useCallback(
    (removedEdges: Edge[], remainingEdges: Edge[]): void => {
      if (removedEdges.length === 0) return;
      setRuntimeState((prev: RuntimeState): RuntimeState =>
        pruneRuntimeInputs(prev, removedEdges, remainingEdges)
      );
    },
    [pruneRuntimeInputs]
  );

  const clearRuntimeForNode = React.useCallback((nodeId: string): void => {
    setRuntimeState((prev: RuntimeState): RuntimeState => {
      const nextInputs = { ...prev.inputs };
      const nextOutputs = { ...prev.outputs };
      const nextHashes = prev.hashes ? { ...prev.hashes } : undefined;
      const nextHistory = prev.history ? { ...prev.history } : undefined;
      delete nextInputs[nodeId];
      delete nextOutputs[nodeId];
      if (nextHashes) {
        delete nextHashes[nodeId];
      }
      if (nextHistory) {
        delete nextHistory[nodeId];
      }
      const result: RuntimeState = {
        ...prev,
        inputs: nextInputs,
        outputs: nextOutputs,
      };
      if (nextHashes !== undefined) result.hashes = nextHashes;
      if (nextHistory !== undefined) result.history = nextHistory;
      return result;
    });
  }, []);

  const {
    viewportRef,
    canvasRef,
    view,
    panState,
    dragState,
    connecting,
    connectingPos,
    lastDrop,
    selectedEdgeId,
    edgePaths,
    connectingFromNode,
    ensureNodeVisible,
    getCanvasCenterPosition,
    handlePointerDown,
    handlePointerMove,
    handlePointerUp,
    handleDragStart,
    handleDrop,
    handleDragOver,
    handleStartConnection,
    handleCompleteConnection,
    handlePanStart,
    handlePanMove,
    handlePanEnd,
    handleReconnectInput,
    handleRemoveEdge,
    handleDisconnectPort,
    handleDeleteSelectedNode,
    handleSelectEdge,
    handleSelectNode,
    zoomTo,
    fitToNodes,
    resetView,
  } = useAiPathsCanvasInteractions({
    nodes,
    setNodes,
    edges,
    setEdges,
    selectedNodeId,
    setSelectedNodeId,
    clearRuntimeInputsForEdges,
    reportAiPathsError,
    toast,
    isPathLocked,
  });

  const selectedNode = useMemo(
    (): AiNode | null =>
      nodes.find((node: AiNode): boolean => node.id === selectedNodeId) ?? null,
    [nodes, selectedNodeId]
  );

  const {
    clusterPresets,
    setClusterPresets,
    dbQueryPresets,
    setDbQueryPresets,
    saveDbQueryPresets,
    dbNodePresets,
    setDbNodePresets,
    saveDbNodePresets,
    editingPresetId,
    presetDraft,
    setPresetDraft,
    handleSavePreset,
    handleLoadPreset,
    handleDeletePreset,
    handleApplyPreset,
    handleExportPresets,
    handleImportPresets,
    handlePresetFromSelection,
    handleResetPresetDraft,
    presetsModalOpen,
    setPresetsModalOpen,
    presetsJson,
    setPresetsJson,
    expandedPaletteGroups,
    setExpandedPaletteGroups,
    paletteCollapsed,
    setPaletteCollapsed,
    togglePaletteGroup,
    normalizeDbQueryPreset,
    normalizeDbNodePreset,
  } = useAiPathsPresets({
    nodes,
    edges,
    selectedNode,
    isPathLocked,
    setNodes,
    setEdges,
    setSelectedNodeId,
    ensureNodeVisible,
    getCanvasCenterPosition,
    toast,
    reportAiPathsError,
  });

  const {
    saving,
    autoSaveStatus,
    autoSaveAt,
    handleSave,
    persistPathSettings,
    persistPreferences,
    persistSettingsBulk,
    savePathIndex,
    syncNodesRef,
  } = useAiPathsPersistence({
    activePathId,
    activeTrigger,
    edges,
    expandedPaletteGroups,
    isPathActive,
    isPathLocked,
    lastRunAt,
    loadNonce,
    loading,
    nodes,
    paletteCollapsed,
    parserSamples,
    pathConfigs,
    pathDescription,
    pathName,
    paths,
    selectedNodeId,
    configOpen,
    runtimeState,
    updaterSamples,
    normalizeDbNodePreset,
    normalizeDbQueryPreset,
    normalizeTriggerLabel,
    persistLastError,
    reportAiPathsError,
    setActivePathId,
    setActiveTrigger,
    setClusterPresets,
    setDbNodePresets,
    setDbQueryPresets,
    setEdges,
    setExpandedPaletteGroups,
    setLastError,
    setLastRunAt,
    setLoading,
    setIsPathActive,
    setIsPathLocked,
    setNodes,
    setPaletteCollapsed,
    setParserSamples,
    setPathConfigs,
    setPathDebugSnapshots,
    setPathDescription,
    setPathName,
    setPaths,
    setRuntimeState,
    setConfigOpen,
    setSelectedNodeId,
    setUpdaterSamples,
    toast,
  });

  const {
    runsQuery,
    runList,
    runFilter,
    setRunFilter,
    expandedRunHistory,
    setExpandedRunHistory,
    runHistorySelection,
    setRunHistorySelection,
    runDetailOpen,
    setRunDetailOpen,
    runDetailLoading,
    runDetail,
    setRunDetail,
    runStreamStatus,
    runStreamPaused,
    setRunStreamPaused,
    runNodeSummary,
    runEventsOverflow,
    runEventsBatchLimit,
    runDetailHistoryOptions,
    runDetailSelectedHistoryNodeId,
    runDetailSelectedHistoryEntries,
    setRunHistoryNodeId,
    handleOpenRunDetail,
    handleResumeRun,
    handleCancelRun,
    handleRequeueDeadLetter,
  } = useAiPathsRunHistory({ activePathId, toast });

  const {
    handleRunSimulation,
    handleFireTrigger,
    handleFireTriggerPersistent,
    handleSendToAi,
    sendingToAi,
  } = useAiPathsRuntime({
    activePathId,
    activeTab,
    activeTrigger,
    isPathActive,
    edges,
    nodes,
    pathDescription,
    pathName,
    parserSamples,
    updaterSamples,
    runtimeState,
    lastRunAt,
    setLastRunAt,
    setPathConfigs,
    setPathDebugSnapshots,
    setRuntimeState,
    toast,
    reportAiPathsError,
  });

  const handleClearWires = async (): Promise<void> => {
    if (!activePathId) return;
    if (isPathLocked) {
      toast("This path is locked. Unlock it to edit nodes or connections.", { variant: "info" });
      return;
    }
    const updatedAt = new Date().toISOString();
    const nextRuntimeState = pruneRuntimeInputs(runtimeState, edges, []);
    if (nextRuntimeState !== runtimeState) {
      setRuntimeState(nextRuntimeState);
    }
    const config: PathConfig = {
      id: activePathId,
      version: STORAGE_VERSION,
      name: pathName,
      description: pathDescription,
      trigger: activeTrigger,
      nodes,
      edges: [],
      updatedAt,
      isLocked: isPathLocked,
      isActive: isPathActive,
      parserSamples,
      updaterSamples,
      runtimeState: nextRuntimeState,
      lastRunAt,
      uiState: {
        selectedNodeId,
        configOpen,
      },
    };
    setEdges([]);
    const nextConfigs = { ...pathConfigs, [activePathId]: config };
    setPathConfigs(nextConfigs);
    try {
      const safeConfigs = serializePathConfigs(nextConfigs);
      await persistPreferences({
        aiPathsPathIndex: paths,
        aiPathsPathConfigs: safeConfigs,
      });
      await persistPathSettings(paths, activePathId, config);
      toast("Wires cleared.", { variant: "success" });
    } catch (error) {
      reportAiPathsError(error, { action: "clearWires" }, "Failed to clear wires:");
      toast("Failed to clear wires.", { variant: "error" });
    }
  };

  const handleClearConnectorData = async (): Promise<void> => {
    if (!activePathId) return;
    if (isPathLocked) {
      toast("This path is locked. Unlock it to edit nodes or connections.", { variant: "info" });
      return;
    }
    const nextRuntimeState: RuntimeState = { inputs: {}, outputs: {} };
    const updatedAt = new Date().toISOString();
    const config: PathConfig = {
      id: activePathId,
      version: STORAGE_VERSION,
      name: pathName,
      description: pathDescription,
      trigger: activeTrigger,
      nodes,
      edges,
      updatedAt,
      isLocked: isPathLocked,
      isActive: isPathActive,
      parserSamples,
      updaterSamples,
      runtimeState: nextRuntimeState,
      lastRunAt,
      uiState: {
        selectedNodeId,
        configOpen,
      },
    };
    setRuntimeState(nextRuntimeState);
    const nextConfigs = { ...pathConfigs, [activePathId]: config };
    setPathConfigs(nextConfigs);
    try {
      const safeConfigs = serializePathConfigs(nextConfigs);
      await persistPreferences({
        aiPathsPathIndex: paths,
        aiPathsPathConfigs: safeConfigs,
      });
      await persistPathSettings(paths, activePathId, config);
      toast("Connector data cleared for current path.", { variant: "success" });
    } catch (error) {
      reportAiPathsError(
        error,
        { action: "clearConnectorData", pathId: activePathId },
        "Failed to clear connector data:"
      );
      toast("Failed to clear connector data.", { variant: "error" });
    }
  };

  const handleClearHistory = async (): Promise<void> => {
    if (!activePathId) return;
    if (isPathLocked) {
      toast("This path is locked. Unlock it to clear history.", { variant: "info" });
      return;
    }
    const currentHistory = runtimeState.history ?? {};
    if (Object.keys(currentHistory).length === 0) {
      toast("No history recorded for this path yet.", { variant: "info" });
      return;
    }
    const nextRuntimeState: RuntimeState = { ...runtimeState };
    delete nextRuntimeState.history;
    const updatedAt = new Date().toISOString();
    const config: PathConfig = {
      id: activePathId,
      version: STORAGE_VERSION,
      name: pathName,
      description: pathDescription,
      trigger: activeTrigger,
      nodes,
      edges,
      updatedAt,
      isLocked: isPathLocked,
      isActive: isPathActive,
      parserSamples,
      updaterSamples,
      runtimeState: nextRuntimeState,
      lastRunAt,
      uiState: {
        selectedNodeId,
        configOpen,
      },
    };
    setRuntimeState(nextRuntimeState);
    const nextConfigs = { ...pathConfigs, [activePathId]: config };
    setPathConfigs(nextConfigs);
    try {
      const safeConfigs = serializePathConfigs(nextConfigs);
      await persistPreferences({
        aiPathsPathIndex: paths,
        aiPathsPathConfigs: safeConfigs,
      });
      await persistPathSettings(paths, activePathId, config);
      toast("History cleared for the current path.", { variant: "success" });
    } catch (error) {
      reportAiPathsError(error, { action: "clearHistory", pathId: activePathId }, "Failed to clear history:");
      toast("Failed to clear history.", { variant: "error" });
    }
  };

  const handleClearNodeHistory = async (nodeId: string): Promise<void> => {
    if (!activePathId) return;
    if (isPathLocked) {
      toast("This path is locked. Unlock it to clear history.", { variant: "info" });
      return;
    }
    const currentHistory = runtimeState.history ?? {};
    if (!currentHistory[nodeId] || currentHistory[nodeId]!.length === 0) {
      toast("No history recorded for this node yet.", { variant: "info" });
      return;
    }
    const nextHistory = { ...currentHistory };
    delete nextHistory[nodeId];
    const nextRuntimeState: RuntimeState = { ...runtimeState };
    if (Object.keys(nextHistory).length > 0) {
      nextRuntimeState.history = nextHistory;
    } else {
      delete nextRuntimeState.history;
    }
    const updatedAt = new Date().toISOString();
    const config: PathConfig = {
      id: activePathId,
      version: STORAGE_VERSION,
      name: pathName,
      description: pathDescription,
      trigger: activeTrigger,
      nodes,
      edges,
      updatedAt,
      isLocked: isPathLocked,
      isActive: isPathActive,
      parserSamples,
      updaterSamples,
      runtimeState: nextRuntimeState,
      lastRunAt,
      uiState: {
        selectedNodeId,
        configOpen,
      },
    };
    setRuntimeState(nextRuntimeState);
    const nextConfigs = { ...pathConfigs, [activePathId]: config };
    setPathConfigs(nextConfigs);
    try {
      const safeConfigs = serializePathConfigs(nextConfigs);
      await persistPreferences({
        aiPathsPathIndex: paths,
        aiPathsPathConfigs: safeConfigs,
      });
      await persistPathSettings(paths, activePathId, config);
      toast("Node history cleared.", { variant: "success" });
    } catch (error) {
      reportAiPathsError(error, { action: "clearNodeHistory", pathId: activePathId, nodeId }, "Failed to clear node history:");
      toast("Failed to clear node history.", { variant: "error" });
    }
  };

  const updateSelectedNode = (patch: Partial<AiNode>): void => {
    if (!selectedNodeId) return;
    if (isPathLocked) {
      toast("This path is locked. Unlock it to edit nodes or connections.", { variant: "info" });
      return;
    }
    const shouldSanitizeEdges = Boolean(patch.inputs || patch.outputs);
    setNodes((prev: AiNode[]): AiNode[] => {
      const next = prev.map((node: AiNode): AiNode =>
        node.id === selectedNodeId ? { ...node, ...patch } : node
      );
      if (shouldSanitizeEdges) {
        setEdges((current: Edge[]): Edge[] => sanitizeEdges(next, current));
      }
      return next;
    });
  };

  const updateSelectedNodeConfig = (patch: NodeConfig): void => {
    if (!selectedNodeId) return;
    if (isPathLocked) {
      toast("This path is locked. Unlock it to edit nodes or connections.", { variant: "info" });
      return;
    }
    setNodes((prev: AiNode[]): AiNode[] => {
      const currentNode = prev.find((node: AiNode): boolean => node.id === selectedNodeId);
      if (!currentNode) return prev;
      const next = prev.map((node: AiNode): AiNode => {
        if (node.id !== selectedNodeId) return node;
        // Deep merge for nested config objects to prevent stale closure issues
        const currentConfig = node.config ?? {};
        const mergedConfig = { ...currentConfig };
        for (const key of Object.keys(patch) as Array<keyof NodeConfig>) {
          const patchValue = patch[key];
          const currentValue = currentConfig[key];
          // Deep merge objects (but not arrays)
          if (
            patchValue &&
            typeof patchValue === "object" &&
            !Array.isArray(patchValue) &&
            currentValue &&
            typeof currentValue === "object" &&
            !Array.isArray(currentValue)
          ) {
            (mergedConfig as Record<string, unknown>)[key] = { ...currentValue, ...patchValue };
          } else {
            (mergedConfig as Record<string, unknown>)[key] = patchValue;
          }
        }
        return { ...node, config: mergedConfig };
      });
      // Update ref synchronously so beforeunload has latest value
      syncNodesRef(next);
      return next;
    });
  };

  // Handler functions that trigger the mutations
  const handleFetchParserSample = async (
    nodeId: string,
    entityType: string,
    entityId: string
  ): Promise<void> => {
    await fetchParserSampleMutation.mutateAsync({ nodeId, entityType, entityId });
  };

  const handleFetchUpdaterSample = async (
    nodeId: string,
    entityType: string,
    entityId: string
  ): Promise<void> => {
    await fetchUpdaterSampleMutation.mutateAsync({ nodeId, entityType, entityId });
  };

  const updateActivePathMeta = (name: string): void => {
    if (!activePathId) return;
    const updatedAt = new Date().toISOString();
    setPaths((prev: PathMeta[]): PathMeta[] =>
      prev.map((path: PathMeta): PathMeta =>
        path.id === activePathId ? { ...path, name, updatedAt } : path
      )
    );
  };

  const handleTogglePathLock = (): void => {
    if (!activePathId) return;
    const nextLocked = !isPathLocked;
    setIsPathLocked(nextLocked);
    setPathConfigs((prev: Record<string, PathConfig>): Record<string, PathConfig> => {
      const base = prev[activePathId] ?? createDefaultPathConfig(activePathId);
      return { ...prev, [activePathId]: { ...base, isLocked: nextLocked } };
    });
    toast(nextLocked ? "Path locked." : "Path unlocked.", { variant: "success" });
  };

  const handleTogglePathActive = (): void => {
    if (!activePathId) return;
    const nextActive = !isPathActive;
    setIsPathActive(nextActive);
    setPathConfigs((prev: Record<string, PathConfig>): Record<string, PathConfig> => {
      const base = prev[activePathId] ?? createDefaultPathConfig(activePathId);
      return { ...prev, [activePathId]: { ...base, isActive: nextActive } };
    });
    toast(nextActive ? "Path activated." : "Path deactivated.", { variant: "success" });
  };

  const handleReset = (): void => {
    if (!activePathId) return;
    if (isPathLocked) {
      toast("This path is locked. Unlock it to edit nodes or connections.", { variant: "info" });
      return;
    }
    const resetConfig = createDefaultPathConfig(activePathId);
    const normalizedNodes = normalizeNodes(resetConfig.nodes);
    setNodes(normalizedNodes);
    setEdges(sanitizeEdges(normalizedNodes, resetConfig.edges));
    setSelectedNodeId(normalizedNodes[0]?.id ?? null);
    setConfigOpen(Boolean(resetConfig.uiState?.configOpen) && Boolean(normalizedNodes[0]?.id));
    setPathName(resetConfig.name);
    setPathDescription(resetConfig.description);
    setActiveTrigger(normalizeTriggerLabel(resetConfig.trigger));
    setParserSamples(resetConfig.parserSamples ?? {});
    setUpdaterSamples(resetConfig.updaterSamples ?? {});
    setIsPathLocked(Boolean(resetConfig.isLocked));
    setIsPathActive(resetConfig.isActive !== false);
    setPathConfigs((prev: Record<string, PathConfig>): Record<string, PathConfig> => ({ ...prev, [activePathId]: resetConfig }));
    updateActivePathMeta(resetConfig.name);
  };

  const handleCreatePath = (): void => {
    const id = createPathId();
    const now = new Date().toISOString();
    const name = `New Path ${paths.length + 1}`;
    const config: PathConfig = {
      id,
      version: STORAGE_VERSION,
      name,
      description: "",
      trigger: triggers[0] ?? "Product Modal - Context Filter",
      nodes: [],
      edges: [],
      updatedAt: now,
      isLocked: false,
      isActive: true,
      parserSamples: {},
      updaterSamples: {},
      runtimeState: { inputs: {}, outputs: {} },
      lastRunAt: null,
      uiState: {
        selectedNodeId: null,
        configOpen: false,
      },
    };
    const meta: PathMeta = {
      id,
      name,
      createdAt: now,
      updatedAt: now,
    };
    setPaths((prev: PathMeta[]): PathMeta[] => [...prev, meta]);
    setPathConfigs((prev: Record<string, PathConfig>): Record<string, PathConfig> => ({ ...prev, [id]: config }));
    setActivePathId(id);
    setNodes([]);
    setEdges([]);
    setPathName(name);
    setPathDescription("");
    setActiveTrigger(normalizeTriggerLabel(config.trigger));
    setParserSamples({});
    setUpdaterSamples({});
    setRuntimeState({ inputs: {}, outputs: {} });
    setLastRunAt(null);
    setIsPathLocked(false);
    setIsPathActive(true);
    setSelectedNodeId(null);
    setConfigOpen(false);
  };

  const handleCreateAiDescriptionPath = (): void => {
    const id = createPathId();
    const config = createAiDescriptionPath(id);
    const now = new Date().toISOString();
    const meta: PathMeta = {
      id,
      name: config.name,
      createdAt: now,
      updatedAt: now,
    };
    setPaths((prev: PathMeta[]): PathMeta[] => [...prev, meta]);
    setPathConfigs((prev: Record<string, PathConfig>): Record<string, PathConfig> => ({ ...prev, [id]: config }));
    setActivePathId(id);
    const normalizedNodes = normalizeNodes(config.nodes);
    setNodes(normalizedNodes);
    setEdges(sanitizeEdges(normalizedNodes, config.edges));
    setPathName(config.name);
    setPathDescription(config.description);
    setActiveTrigger(normalizeTriggerLabel(config.trigger));
    setParserSamples(config.parserSamples ?? {});
    setUpdaterSamples(config.updaterSamples ?? {});
    setRuntimeState(parseRuntimeState(config.runtimeState));
    setLastRunAt(config.lastRunAt ?? null);
    setIsPathLocked(Boolean(config.isLocked));
    setIsPathActive(config.isActive !== false);
    const preferredNodeId = config.uiState?.selectedNodeId ?? null;
    const resolvedNodeId =
      preferredNodeId && normalizedNodes.some((node: AiNode): boolean => node.id === preferredNodeId)
        ? preferredNodeId
        : normalizedNodes[0]?.id ?? null;
    setSelectedNodeId(resolvedNodeId);
    setConfigOpen(Boolean(config.uiState?.configOpen) && Boolean(resolvedNodeId));
    toast("AI Description Path created.", { variant: "success" });
  };

  const handleDeletePath = async (pathId?: string): Promise<void> => {
    const targetId = pathId ?? activePathId;
    if (!targetId) return;
    const nextPaths = paths.filter((path: PathMeta): boolean => path.id !== targetId);
    if (nextPaths.length === 0) {
      const fallbackId = "default";
      const fallback = createDefaultPathConfig(fallbackId);
      const fallbackMeta = createPathMeta(fallback);
      setPaths([fallbackMeta]);
      setPathConfigs({ [fallbackId]: fallback });
      setActivePathId(fallbackId);
      const normalizedNodes = normalizeNodes(fallback.nodes);
      setNodes(normalizedNodes);
      setEdges(sanitizeEdges(normalizedNodes, fallback.edges));
      setPathName(fallback.name);
      setPathDescription(fallback.description);
      setActiveTrigger(normalizeTriggerLabel(fallback.trigger));
      setParserSamples(fallback.parserSamples ?? {});
      setUpdaterSamples(fallback.updaterSamples ?? {});
      setRuntimeState(parseRuntimeState(fallback.runtimeState));
      setLastRunAt(fallback.lastRunAt ?? null);
      setIsPathLocked(Boolean(fallback.isLocked));
      setIsPathActive(fallback.isActive !== false);
      const fallbackNodeId = normalizedNodes[0]?.id ?? null;
      setSelectedNodeId(fallbackNodeId);
      setConfigOpen(Boolean(fallback.uiState?.configOpen) && Boolean(fallbackNodeId));
      toast("Cannot delete the last path. Reset to default instead.", {
        variant: "info",
      });
      return;
    }
    const nextId = nextPaths[0]?.id ?? null;
    setPaths(nextPaths);
    const nextConfigs = { ...pathConfigs };
    delete nextConfigs[targetId];
    setPathConfigs(nextConfigs);
    if (nextId) {
      const nextConfig = pathConfigs[nextId] ?? createDefaultPathConfig(nextId);
      setActivePathId(nextId);
      const normalizedNodes = normalizeNodes(nextConfig.nodes);
      setNodes(normalizedNodes);
      setEdges(sanitizeEdges(normalizedNodes, nextConfig.edges));
      setPathName(nextConfig.name);
      setPathDescription(nextConfig.description);
      setActiveTrigger(normalizeTriggerLabel(nextConfig.trigger));
      setParserSamples(nextConfig.parserSamples ?? {});
      setUpdaterSamples(nextConfig.updaterSamples ?? {});
      setRuntimeState(parseRuntimeState(nextConfig.runtimeState));
      setLastRunAt(nextConfig.lastRunAt ?? null);
      setIsPathLocked(Boolean(nextConfig.isLocked));
      setIsPathActive(nextConfig.isActive !== false);
      const preferredNodeId = nextConfig.uiState?.selectedNodeId ?? null;
      const resolvedNodeId =
        preferredNodeId && normalizedNodes.some((node: AiNode): boolean => node.id === preferredNodeId)
          ? preferredNodeId
          : normalizedNodes[0]?.id ?? null;
      setSelectedNodeId(resolvedNodeId);
      setConfigOpen(Boolean(nextConfig.uiState?.configOpen) && Boolean(resolvedNodeId));
    } else {
      setActivePathId(null);
    }
    try {
      const safeConfigs = serializePathConfigs(nextConfigs);
      await persistPreferences({
        aiPathsPathIndex: nextPaths,
        aiPathsPathConfigs: safeConfigs,
      });
      if (nextId) {
        const nextConfig = nextConfigs[nextId] ?? createDefaultPathConfig(nextId);
        await persistPathSettings(nextPaths, nextId, nextConfig);
      } else {
        await persistSettingsBulk([
          { key: PATH_INDEX_KEY, value: JSON.stringify(nextPaths) },
        ]);
      }
      toast("Path removed from the index.", { variant: "success" });
    } catch (error) {
      reportAiPathsError(error, { action: "deletePath", pathId: targetId }, "Failed to update path index:");
      toast("Failed to update path index.", { variant: "error" });
    }
  };

  const handleSwitchPath = (value: string): void => {
    if (!value) return;
    const config = pathConfigs[value] ?? createDefaultPathConfig(value);
    setActivePathId(value);
    const normalizedNodes = normalizeNodes(config.nodes);
    setNodes(normalizedNodes);
    setEdges(sanitizeEdges(normalizedNodes, config.edges));
    setPathName(config.name);
    setPathDescription(config.description);
    setActiveTrigger(normalizeTriggerLabel(config.trigger));
    setParserSamples(config.parserSamples ?? {});
    setUpdaterSamples(config.updaterSamples ?? {});
    setRuntimeState(parseRuntimeState(config.runtimeState));
    setLastRunAt(config.lastRunAt ?? null);
    setIsPathLocked(Boolean(config.isLocked));
    setIsPathActive(config.isActive !== false);
    const preferredNodeId = config.uiState?.selectedNodeId ?? null;
    const resolvedNodeId =
      preferredNodeId && normalizedNodes.some((node: AiNode): boolean => node.id === preferredNodeId)
        ? preferredNodeId
        : normalizedNodes[0]?.id ?? null;
    setSelectedNodeId(resolvedNodeId);
    setConfigOpen(Boolean(config.uiState?.configOpen) && Boolean(resolvedNodeId));
  };

  const handleCopyDocsWiring = async (): Promise<void> => {
    try {
      await navigator.clipboard.writeText(DOCS_WIRING_SNIPPET);
      toast("Wiring copied to clipboard.", { variant: "success" });
    } catch (error) {
      reportAiPathsError(error, { action: "copyDocsWiring" }, "Failed to copy wiring:");
      toast("Failed to copy wiring.", { variant: "error" });
    }
  };

  const handleCopyDocsDescription = async (): Promise<void> => {
    try {
      await navigator.clipboard.writeText(DOCS_DESCRIPTION_SNIPPET);
      toast("AI Description wiring copied.", { variant: "success" });
    } catch (error) {
      reportAiPathsError(error, { action: "copyDocsDescription" }, "Failed to copy wiring:");
      toast("Failed to copy wiring.", { variant: "error" });
    }
