    setLearnOpen(true);
    setLearnLoading(true);
    try {
      const res = await fetch("/api/image-studio/validation-patterns/learn", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          prompt: promptText,
          limit: 8,
