    const clamped = points.map((p) => ({ x: clamp01(p.x), y: clamp01(p.y) }));
    const newShape: MaskShape = {
      id: `shape_${Date.now().toString(36)}`,
      name,
      type: "polygon",
      points: clamped,
      closed: true,
      visible: true,
