            sectionType={sectionType}
            sectionZone={sectionZone}
            columnId={columnId}
            parentBlockId={block.id}
            onOpenMedia={onOpenMedia}
            mediaStyles={mediaStyles}
            stretch={shouldStretchChildren}
          />
        ))}
      </div>
