interface FieldProps<T> {
  label?: string;
  value: T;
  onChange: (value: T) => void;
  className?: string;
  disabled?: boolean;
}

export function ImagePickerField({
  label,
  value,
  onChange,
  disabled,
}: FieldProps<string>): React.JSX.Element {
  const [open, setOpen] = useState(false);
  const fileInputRef = useRef<HTMLInputElement | null>(null);
  const uploadMutation = useUploadCmsMedia();
  const { toast } = useToast();

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>): Promise<void> => {
    const file = event.target.files?.[0];
    event.target.value = "";
    if (!file) return;

    try {
      const result = await uploadMutation.mutateAsync(file);
      if (result.filepath) {
        onChange(result.filepath);
        toast("Image uploaded successfully.", { variant: "success" });
      }
    } catch (error) {
      const message = error instanceof Error ? error.message : "Upload failed";
      toast(message, { variant: "error" });
    }
  };

  const isUploading = uploadMutation.isPending;

  return (
    <div className="space-y-2">
      {label && (
        <Label className="text-[10px] uppercase tracking-wider text-gray-500">
          {label}
        </Label>
      )}
      <div className="relative flex h-28 items-center justify-center overflow-hidden rounded border border-dashed border-border/50 bg-gray-800/30">
        {value ? (
          <NextImage
            src={value}
            alt="Selected"
            fill
            sizes="320px"
            className="object-cover"
            unoptimized
          />
        ) : (
          <span className="text-xs text-gray-500">No image</span>
        )}
        {isUploading && (
          <div className="absolute inset-0 flex items-center justify-center bg-black/50">
            <Loader2 className="size-6 animate-spin text-white" />
          </div>
        )}
      </div>
      <input
        ref={fileInputRef}
        type="file"
        accept="image/*"
        className="hidden"
        onChange={(e: React.ChangeEvent<HTMLInputElement>): void => { void handleFileUpload(e); }}
      />
      <div className="grid grid-cols-2 gap-2">
        <Button
          type="button"
          size="sm"
          variant="outline"
          className="text-xs"
          onClick={(): void => fileInputRef.current?.click()}
          disabled={disabled || isUploading}
        >
          <Upload className="mr-1.5 size-3" />
          {value ? "Replace" : "Upload"}
        </Button>
        <Button
          type="button"
          size="sm"
          variant="outline"
          className="text-xs"
          onClick={(): void => setOpen(true)}
          disabled={disabled || isUploading}
        >
          <FolderOpen className="mr-1.5 size-3" />
          Browse
        </Button>
      </div>
      {value ? (
        <Button
          type="button"
          size="sm"
          variant="ghost"
          className="w-full text-xs text-gray-400 hover:text-gray-200"
          onClick={(): void => onChange("")}
          disabled={disabled || isUploading}
        >
          Clear image
        </Button>
      ) : null}
      <MediaLibraryPanel
        open={open}
        onOpenChange={setOpen}
        selectionMode="single"
        onSelect={(filepaths: string[]): void => onChange(filepaths[0] ?? "")}
      />
    </div>
  );
}

