  const categories = categoriesQuery.data ?? [];
  const tags = tagsQuery.data ?? [];
  const selectedAsset = selectedAssetQuery.data ?? null;
  const modelUrl = selectedAsset ? `/api/assets3d/${selectedAsset.id}/file` : null;

