          Preview
        </Button>
      </div>
      {value ? (
        <Button
          type="button"
          size="sm"
          variant="ghost"
          className="w-full text-xs text-gray-400 hover:text-gray-200"
          onClick={(): void => onChange("")}
          disabled={disabled}
