// Enhanced model component with PBR material optimization
interface Model3DProps {
  url: string;
  onLoad?: () => void;
  onError?: (error: Error) => void;
  castShadow?: boolean;
  receiveShadow?: boolean;
  position?: [number, number, number];
  rotation?: [number, number, number];
  scale?: number | [number, number, number];
}

function AutoRotateGroup({
  enabled,
  speed,
  children,
}: {
  enabled: boolean;
  speed: number;
  children: React.ReactNode;
}): React.JSX.Element {
  const ref = useRef<THREE.Group>(null);
  useFrame((_, delta) => {
    if (!enabled || !ref.current) return;
    ref.current.rotation.y += delta * speed * 0.6;
  });
  return <group ref={ref}>{children}</group>;
}

function Model3D({
  url,
  onLoad,
  onError,
  castShadow = true,
  receiveShadow = true,
  position,
  rotation,
  scale,
}: Model3DProps): React.JSX.Element {
  const { scene } = useGLTF(url, true); // Enable error handling
  const modelRef = useRef<THREE.Group>(null);

  useEffect(() => {
    if (scene) {
      // Optimize materials for PBR rendering
      scene.traverse((child: THREE.Object3D) => {
        if (child instanceof THREE.Mesh) {
          child.castShadow = castShadow;
          child.receiveShadow = receiveShadow;

          // Enhance material properties for better realism
          if (child.material instanceof THREE.MeshStandardMaterial) {
            child.material.envMapIntensity = 1.5;
            child.material.needsUpdate = true;
          }
        }
      });
      onLoad?.();
    }
  }, [scene, onLoad, castShadow, receiveShadow]);

  useEffect(() => {
    if (!scene && onError) {
      onError(new Error("Failed to load model"));
    }
  }, [scene, onError]);

  if (!scene) {
    return (
      <Html center>
        <div className="text-red-400 text-center p-4 bg-black/50 rounded">
          <p>Model not found</p>
          <p className="text-sm text-gray-400 mt-2">
            The 3D asset could not be loaded
          </p>
        </div>
      </Html>
    );
  }

  /* eslint-disable react/no-unknown-property */
  return (
    <primitive
      ref={modelRef}
      object={scene}
      dispose={null}
      position={position}
      rotation={rotation}
      scale={scale}
    />
  );
  /* eslint-enable react/no-unknown-property */
}

