import "server-only";

import { NextRequest, NextResponse } from "next/server";
import { randomUUID } from "crypto";
import { resolveError } from "@/shared/errors/resolve-error";
import { badRequestError } from "@/shared/errors/app-error";
import type { SystemLogLevel } from "@/shared/types/system-logs";
import type {
  ApiHandlerOptions,
  ApiHandlerContext,
  ApiRouteHandler,
  ApiRouteHandlerWithParams,
} from "@/shared/types/api";

// Local type definitions to avoid importing from features layer
type LogSystemEventParams = {
  level: SystemLogLevel;
  message: string;
  source: string;
  error?: unknown;
  request?: NextRequest;
  requestId?: string;
  statusCode?: number;
  context?: Record<string, unknown>;
};

type ErrorFingerprintParams = {
  message: string;
  source: string;
  request: NextRequest;
  statusCode: number;
  error: unknown;
};

// Stub implementations to avoid features layer dependency
const logSystemEvent = (params: LogSystemEventParams): void => {
  // Implementation would be injected or moved to shared layer
  console.log('System event:', params);
};

const getErrorFingerprint = (params: ErrorFingerprintParams): string => {
  // Simple fingerprint generation
  return `${params.source}-${params.statusCode}-${Date.now()}`;
};

export type {
  ApiHandlerOptions,
  ApiHandlerContext,
  ApiRouteHandler,
  ApiRouteHandlerWithParams,
};

/**
 * Wraps an API route handler with automatic error handling, logging, and request tracking.
 *
 * Features:
 * - Automatic error catching and standardized error responses
 * - Request ID generation and tracking
 * - Performance timing
 * - Structured logging for both errors and successes
 * - Consistent error response format
 *
 * @example
 * ```ts
 * export const GET = apiHandler(
 *   async (req, ctx) => {
 *     const data = await fetchData();
 *     return NextResponse.json(data);
 *   },
 *   { source: "products.GET" }
 * );
 * ```
 */
export function apiHandler(
  handler: ApiRouteHandler,
  options: ApiHandlerOptions
): (request: NextRequest) => Promise<Response> {
  return async (request: NextRequest) => {
    const requestId = request.headers.get("x-request-id") ?? randomUUID();
    const startTime = performance.now();

    const context: ApiHandlerContext = {
      requestId,
      startTime,
      getElapsedMs: (): number => Math.round(performance.now() - startTime),
    };

    try {
      const response = await handler(request, context);

      // Log successful requests if configured
      if (options.logSuccess) {
        void logSystemEvent({
          level: options.successLogLevel ?? "info",
          message: `${options.source} completed successfully`,
          source: options.source,
          request,
          requestId,
          statusCode: response.status,
          context: {
            durationMs: context.getElapsedMs(),
          },
        });
      }

      // Add request ID to response headers for client-side tracking
      if (!response.headers.has("x-request-id")) {
        response.headers.set("x-request-id", requestId);
      }
      applyDefaultCacheHeaders(response, request.method, options.cacheControl);
      return response;
    } catch (error) {
      return createErrorResponseWithTiming(error, request, context, options);
    }
  };
}

/**
 * Wraps an API route handler with params (for dynamic routes like [id]).
 *
 * @example
 * ```ts
 * export const GET = apiHandlerWithParams<{ id: string }>(
 *   async (req, ctx, params) => {
 *     const item = await getById(params.id);
 *     return NextResponse.json(item);
 *   },
 *   { source: "products/[id].GET" }
 * );
 * ```
 */
export function apiHandlerWithParams<P extends Record<string, string>>(
  handler: ApiRouteHandlerWithParams<P>,
  options: ApiHandlerOptions
): (
  request: NextRequest,
  context: { params: Promise<P> }
) => Promise<Response> {
  return async (request: NextRequest, routeContext: { params: Promise<P> }) => {
    const requestId = request.headers.get("x-request-id") ?? randomUUID();
    const startTime = performance.now();

    const handlerContext: ApiHandlerContext = {
      requestId,
      startTime,
      getElapsedMs: () => Math.round(performance.now() - startTime),
    };

    try {
      const params = await routeContext.params;
      const response = await handler(request, handlerContext, params);

      if (options.logSuccess) {
        void logSystemEvent({
          level: options.successLogLevel ?? "info",
          message: `${options.source} completed successfully`,
          source: options.source,
          request,
          requestId,
          statusCode: response.status,
          context: {
            durationMs: handlerContext.getElapsedMs(),
            params,
          },
        });
      }

      if (!response.headers.has("x-request-id")) {
        response.headers.set("x-request-id", requestId);
      }
      applyDefaultCacheHeaders(response, request.method, options.cacheControl);
      return response;
    } catch (error) {
      return createErrorResponseWithTiming(
        error,
        request,
        handlerContext,
        options
      );
    }
  };
}

const DEFAULT_GET_CACHE_CONTROL = "private, max-age=60, stale-while-revalidate=300";

function applyDefaultCacheHeaders(
  response: Response,
  method: string,
  override?: string | undefined
): void {
  if (response.headers.has("Cache-Control")) return;
  if (override && override.trim()) {
    response.headers.set("Cache-Control", override.trim());
    return;
  }
  const isGetLike = method === "GET" || method === "HEAD";
  if (isGetLike) {
    response.headers.set("Cache-Control", DEFAULT_GET_CACHE_CONTROL);
    return;
  }
  response.headers.set("Cache-Control", "no-store");
}

/**
 * Creates an error response with timing information and logging.
 */
function createErrorResponseWithTiming(
  error: unknown,
  request: NextRequest,
  context: ApiHandlerContext,
  options: ApiHandlerOptions
): Response {
  const resolved = resolveError(error, {
    ...(options.fallbackMessage !== undefined && { fallbackMessage: options.fallbackMessage }),
  });

  const level: SystemLogLevel = resolved.expected ? "warn" : "error";
  const durationMs = context.getElapsedMs();

  // Log the error with full context
  void logSystemEvent({
    level,
    message: resolved.message,
    source: options.source,
    error,
    request,
    requestId: context.requestId,
    statusCode: resolved.httpStatus,
    context: {
      errorId: resolved.errorId,
      code: resolved.code,
      durationMs,
      ...(resolved.meta ? { meta: resolved.meta } : {}),
    },
  });

  // Build response payload
  const payload: Record<string, unknown> = {
    error: resolved.message,
    code: resolved.code,
    errorId: resolved.errorId,
  };

  const fingerprint = getErrorFingerprint({
    message: resolved.message,
    source: options.source,
    request,
    statusCode: resolved.httpStatus,
    error,
  });

  payload.fingerprint = fingerprint;

  if (resolved.retryable) {
    payload.retryable = true;
    if (resolved.retryAfterMs) {
      payload.retryAfterMs = resolved.retryAfterMs;
    }
  }

  if (resolved.expected && resolved.meta) {
    payload.details = resolved.meta;
  } else if (options.includeDetails && resolved.meta) {
    payload.details = resolved.meta;
  }

  const response = NextResponse.json(payload, { status: resolved.httpStatus });
  response.headers.set("x-request-id", context.requestId);
  response.headers.set("x-error-id", resolved.errorId);
  response.headers.set("x-error-fingerprint", fingerprint);

  if (resolved.retryable && resolved.retryAfterMs) {
    const retryAfterSeconds = Math.ceil(resolved.retryAfterMs / 1000);
    response.headers.set("Retry-After", String(retryAfterSeconds));
  }

  return response;
}

/**
 * Helper to extract common query parameters.
 */
export function getQueryParams(request: NextRequest): URLSearchParams {
  return new URL(request.url).searchParams;
}

/**
 * Helper to get a required query parameter, throws if missing.
 */
export function getRequiredParam(
  searchParams: URLSearchParams,
  name: string
): string {
  const value = searchParams.get(name);
  if (!value) {
    throw badRequestError(`Missing required parameter: ${name}`);
  }
  return value;
}

/**
 * Helper to parse pagination parameters.
 */
export function getPaginationParams(searchParams: URLSearchParams): {
  page: number;
  pageSize: number;
  skip: number;
} {
  const page = Math.max(1, parseInt(searchParams.get("page") ?? "1", 10));
  const pageSize = Math.min(
    100,
    Math.max(1, parseInt(searchParams.get("pageSize") ?? "20", 10))
  );
  const skip = (page - 1) * pageSize;
  return { page, pageSize, skip };
}

import { cva, type VariantProps } from "class-variance-authority";
import * as React from "react";
import { Loader2 } from "lucide-react";

import { cn } from "@/shared/utils";

const buttonVariants = cva(
  "inline-flex items-center justify-center whitespace-nowrap rounded-lg border border-transparent text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring/40 focus-visible:ring-offset-2 disabled:pointer-events-none disabled:cursor-not-allowed disabled:opacity-50 ring-offset-background cursor-pointer",
  {
    variants: {
      variant: {
        default:
          "bg-transparent hover:bg-foreground/10",
        destructive:
          "bg-destructive/15 text-destructive hover:bg-destructive/25",
        outline:
          "border-foreground/15 bg-transparent hover:bg-foreground/8",
        secondary:
          "bg-muted/30 hover:bg-muted/45",
        ghost: "bg-transparent hover:bg-foreground/8",
        link: "text-foreground/80 underline-offset-4 hover:underline hover:text-foreground",
      },
      size: {
        default: "h-9 px-3.5 py-2",
        sm: "h-8 rounded-lg px-3",
        lg: "h-10 rounded-lg px-4",
        icon: "size-9 rounded-full",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  }
)

const mergeProps = (
  slotProps: Record<string, unknown>,
  childProps: Record<string, unknown>
): Record<string, unknown> => {
  const overrideProps: Record<string, unknown> = { ...childProps };
  Object.keys(slotProps).forEach((propName) => {
    const slotPropValue = slotProps[propName];
    const childPropValue = childProps[propName];
    const isHandler = /^on[A-Z]/.test(propName);
    if (
      isHandler &&
      typeof slotPropValue === "function" &&
      typeof childPropValue === "function"
    ) {
      overrideProps[propName] = (...args: unknown[]) => {
        (childPropValue as (...eventArgs: unknown[]) => void)(...args);
        (slotPropValue as (...eventArgs: unknown[]) => void)(...args);
      };
    } else if (slotPropValue !== undefined) {
      overrideProps[propName] = slotPropValue;
    }
  });
  return overrideProps;
};

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean;
  loading?: boolean;
  loadingText?: string;
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, loading = false, loadingText, children, ...props }, ref) => {
    if (asChild && React.isValidElement(children)) {
      const child = children as React.ReactElement<{ children?: React.ReactNode }>;
      const childContent = loading ? (
        <>
          <Loader2 className="size-4 animate-spin" />
          {loading && loadingText ? loadingText : child.props.children}
        </>
      ) : (
        child.props.children
      );
      const mergedClassName = cn(
        buttonVariants({ variant, size, className }),
        child.props.className,
        loading && "gap-2"
      );
      const mergedProps = mergeProps(
        {
          ...props,
          className: mergedClassName,
          disabled: loading || props.disabled,
          ref,
        },
        child.props
      );
      return React.cloneElement(child, mergedProps, childContent);
    }

    const baseContent = loading && loadingText ? loadingText : children
    const content = loading ? (
      <>
        <Loader2 className="size-4 animate-spin" />
        {baseContent}
      </>
    ) : (
      baseContent
    )
    return (
      <button
        className={cn(buttonVariants({ variant, size, className }), loading && "gap-2")}
        ref={ref}
        disabled={loading || props.disabled}
        {...props}
      >
        {content}
      </button>
    )
  }
)
Button.displayName = "Button"

export { Button, buttonVariants }

